import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const geminiService = {
  async generateProjectStarter(skills: string[], interest: string) {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Suggest a coding project for a developer with skills: ${skills.join(", ")} interested in: ${interest}. Provide the response in JSON format.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            roadmap: { type: Type.ARRAY, items: { type: Type.STRING } },
            starterFiles: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  content: { type: Type.STRING },
                  language: { type: Type.STRING }
                },
                required: ["name", "content", "language"]
              }
            }
          },
          required: ["title", "description", "roadmap", "starterFiles"]
        }
      }
    });

    return JSON.parse(response.text);
  },

  async calculateReputation(projectData: string) {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Evaluate this project code and structure. Assign a reputation score (0-100) based on complexity and best practices. Return JSON.
      Data: ${projectData}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            score: { type: Type.NUMBER },
            feedback: { type: Type.STRING }
          },
          required: ["score", "feedback"]
        }
      }
    });

    return JSON.parse(response.text);
  }
};

import { useState, useEffect, useCallback } from 'react';
import { User, Project, Message, Theme, AppState } from '../types';

const STORAGE_KEY = 'vortex_data';

const initialUser: User = {
  id: 'u1',
  name: 'Investor Demo',
  email: 'demo@vortex.io',
  avatar: 'https://picsum.photos/seed/vortex/200',
  bio: 'Silicon Valley Visionary | Backend Enthusiast',
  skills: ['React', 'TypeScript', 'Node.js', 'PostgreSQL'],
  coins: 12500,
  reputation: 85,
  hasSkillBadge: true
};

export function useVortexState() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) return JSON.parse(saved);
    return {
      currentUser: initialUser,
      projects: [],
      messages: [],
      theme: Theme.DARK
    };
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const setTheme = useCallback((theme: Theme) => {
    setState(prev => ({ ...prev, theme }));
    document.documentElement.className = theme === Theme.DIM ? 'dark' : theme;
    if (theme === Theme.DIM) {
        document.body.className = 'bg-dim text-gray-100 transition-colors duration-300';
    } else if (theme === Theme.DARK) {
        document.body.className = 'bg-gray-900 text-gray-100 transition-colors duration-300';
    } else {
        document.body.className = 'bg-gray-50 text-gray-900 transition-colors duration-300';
    }
  }, []);

  const addProject = useCallback((project: Project) => {
    setState(prev => ({
      ...prev,
      projects: [project, ...prev.projects],
      currentUser: prev.currentUser ? { ...prev.currentUser, coins: prev.currentUser.coins + 500 } : null
    }));
  }, []);

  const reactToProject = useCallback((projectId: string, type: 'like' | 'love' | 'laugh' | 'dislike') => {
    setState(prev => {
      const projects = prev.projects.map(p => {
        if (p.id === projectId) {
          return {
            ...p,
            reactions: {
              ...p.reactions,
              [type]: p.reactions[type] + 1
            }
          };
        }
        return p;
      });

      const coinDelta = type === 'dislike' ? -50 : 100;
      return {
        ...prev,
        projects,
        currentUser: prev.currentUser ? { ...prev.currentUser, coins: prev.currentUser.coins + coinDelta } : null
      };
    });
  }, []);

  const sendMessage = useCallback((msg: Message) => {
    setState(prev => ({
      ...prev,
      messages: [...prev.messages, msg]
    }));
  }, []);

  return {
    ...state,
    setTheme,
    addProject,
    reactToProject,
    sendMessage
  };
}

