import React, { useState } from 'react';
import { geminiService } from '../services/gemini';
import { AppState, Project } from '../types';

interface AIStarterProps {
  state: AppState;
  onProjectCreated: (p: Project) => void;
}

const AIStarter: React.FC<AIStarterProps> = ({ state, onProjectCreated }) => {
  const [interest, setInterest] = useState('');
  const [loading, setLoading] = useState(false);
  const [suggestion, setSuggestion] = useState<any>(null);

  const handleGenerate = async () => {
    if (!interest || !state.currentUser) return;
    setLoading(true);
    try {
      const result = await geminiService.generateProjectStarter(state.currentUser.skills, interest);
      setSuggestion(result);
    } catch (e) {
      console.error(e);
      alert('Error generating suggestion. Check API key.');
    } finally {
      setLoading(false);
    }
  };

  const handleLaunch = () => {
    if (!suggestion || !state.currentUser) return;
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      ownerId: state.currentUser.id,
      title: suggestion.title,
      description: suggestion.description,
      files: suggestion.starterFiles,
      roadmap: suggestion.roadmap,
      reactions: { like: 0, love: 0, laugh: 0, dislike: 0 },
      isPublic: true,
      createdAt: new Date().toISOString(),
      reputationScore: 0
    };
    onProjectCreated(newProject);
    alert('Project Launched! Check your Dashboard.');
    setSuggestion(null);
    setInterest('');
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in zoom-in duration-300">
      <div className="text-center space-y-4">
        <h2 className="text-4xl font-extrabold tracking-tight">VORTEX <span className="text-indigo-600">AI GENESIS</span></h2>
        <p className="text-lg opacity-60">Generate investor-ready codebases and roadmaps based on your skills.</p>
      </div>

      <div className="bg-white dark:bg-gray-800 p-8 rounded-3xl shadow-xl border border-indigo-500/20">
        <div className="space-y-6">
          <div>
            <label className="block text-sm font-bold mb-2 uppercase tracking-wide opacity-50">What are you looking to build?</label>
            <div className="relative">
              <input 
                type="text" 
                value={interest}
                onChange={(e) => setInterest(e.target.value)}
                placeholder="e.g., A real-time stock tracker using web sockets..."
                className="w-full bg-gray-50 dark:bg-gray-900 border-2 border-transparent focus:border-indigo-500 rounded-2xl px-6 py-4 text-lg outline-none transition-all shadow-inner"
              />
              <button 
                onClick={handleGenerate}
                disabled={loading || !interest}
                className="absolute right-2 top-2 bottom-2 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-8 rounded-xl font-bold transition-all flex items-center gap-2"
              >
                {loading ? (
                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                ) : 'GENERATE'}
              </button>
            </div>
          </div>

          <div className="flex flex-wrap gap-2">
            <span className="text-xs font-bold uppercase opacity-40">Your Skills context:</span>
            {state.currentUser?.skills.map(s => (
              <span key={s} className="px-3 py-1 bg-indigo-500/10 text-indigo-500 rounded-full text-xs font-bold border border-indigo-500/20">{s}</span>
            ))}
          </div>
        </div>
      </div>

      {suggestion && (
        <div className="animate-in fade-in slide-in-from-top-8 duration-500 space-y-6">
          <div className="bg-white dark:bg-gray-800 rounded-3xl p-8 border border-gray-100 dark:border-gray-700 shadow-lg">
            <div className="flex justify-between items-start mb-6">
              <div>
                <h3 className="text-2xl font-bold mb-2">{suggestion.title}</h3>
                <p className="opacity-70 leading-relaxed">{suggestion.description}</p>
              </div>
              <button 
                onClick={handleLaunch}
                className="bg-green-600 hover:bg-green-700 text-white px-8 py-3 rounded-2xl font-bold shadow-lg shadow-green-500/20 transition-all"
              >
                LAUNCH PROJECT
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div>
                <h4 className="text-sm font-bold uppercase tracking-widest text-indigo-500 mb-4">Project Roadmap</h4>
                <ul className="space-y-3">
                  {suggestion.roadmap.map((step: string, i: number) => (
                    <li key={i} className="flex gap-3 text-sm">
                      <span className="flex-shrink-0 w-6 h-6 bg-indigo-500 text-white rounded-full flex items-center justify-center font-bold text-xs">{i + 1}</span>
                      {step}
                    </li>
                  ))}
                </ul>
              </div>
              <div>
                <h4 className="text-sm font-bold uppercase tracking-widest text-indigo-500 mb-4">Starter Architecture</h4>
                <div className="bg-gray-900 rounded-xl p-4 font-mono text-xs text-green-400 max-h-48 overflow-y-auto">
                  {suggestion.starterFiles.map((f: any) => (
                    <div key={f.name} className="mb-2">
                      <span className="opacity-50"># {f.name}</span>
                      <pre className="mt-1 opacity-80">{f.content.slice(0, 50)}...</pre>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AIStarter;

import React, { useState } from 'react';
import { AppState, Message } from '../types';

interface ChatProps {
  state: AppState;
  onSendMessage: (msg: Message) => void;
}

const DEMO_CONTACTS = [
  { id: 'u2', name: 'Sarah Developer', avatar: 'https://picsum.photos/seed/sarah/40', status: 'online' },
  { id: 'u3', name: 'James HR', avatar: 'https://picsum.photos/seed/james/40', status: 'offline' },
  { id: 'u4', name: 'Vector AI', avatar: 'https://picsum.photos/seed/ai/40', status: 'online' },
];

const Chat: React.FC<ChatProps> = ({ state, onSendMessage }) => {
  const [selectedContact, setSelectedContact] = useState(DEMO_CONTACTS[0]);
  const [text, setText] = useState('');

  const chatMessages = state.messages.filter(m => 
    (m.senderId === state.currentUser?.id && m.receiverId === selectedContact.id) ||
    (m.senderId === selectedContact.id && m.receiverId === state.currentUser?.id)
  );

  const handleSend = () => {
    if (!text.trim() || !state.currentUser) return;
    const newMsg: Message = {
      id: Math.random().toString(),
      senderId: state.currentUser.id,
      receiverId: selectedContact.id,
      content: text,
      timestamp: new Date().toISOString()
    };
    onSendMessage(newMsg);
    setText('');
  };

  return (
    <div className="flex h-full rounded-2xl overflow-hidden border border-gray-100 dark:border-gray-700 shadow-lg bg-white dark:bg-gray-800">
      <div className="w-80 border-r dark:border-gray-700 flex flex-col">
        <div className="p-4 border-b dark:border-gray-700">
          <input 
            type="text" 
            placeholder="Search messages..." 
            className="w-full px-4 py-2 bg-gray-100 dark:bg-gray-900 rounded-lg text-sm outline-none"
          />
        </div>
        <div className="flex-1 overflow-y-auto">
          {DEMO_CONTACTS.map(c => (
