                <img src={c.avatar} className="w-12 h-12 rounded-full" alt="" />
                {c.status === 'online' && <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 border-2 border-white dark:border-gray-800 rounded-full"></div>}
