import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, Modality } from '@google/genai';

interface CallingUIProps {
  isOpen: boolean;
  onClose: () => void;
  contactName: string;
  contactAvatar: string;
}

const CallingUI: React.FC<CallingUIProps> = ({ isOpen, onClose, contactName, contactAvatar }) => {
  const [isConnected, setIsConnected] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [callDuration, setCallDuration] = useState(0);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);

  useEffect(() => {
    let interval: any;
    if (isConnected) {
      interval = setInterval(() => setCallDuration(prev => prev + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [isConnected]);

  const formatTime = (s: number) => {
    const mins = Math.floor(s / 60);
    const secs = s % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const startCall = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: `You are ${contactName}, a world-class senior developer. Help the user with their VORTEX projects, code reviews, and career advice. Be friendly, slightly witty, and highly technical.`
        },
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            const source = inputCtx.createMediaStreamSource(stream);
            const processor = inputCtx.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const input = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(input.length);
              for (let i = 0; i < input.length; i++) int16[i] = input[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor);
            processor.connect(inputCtx.destination);
          },
          onmessage: async (msg) => {
            const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              const binary = atob(audioData);
              const bytes = new Uint8Array(binary.length);
              for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
              const dataInt16 = new Int16Array(bytes.buffer);
              const buffer = outputCtx.createBuffer(1, dataInt16.length, 24000);
              const channelData = buffer.getChannelData(0);
              for (let i = 0; i < dataInt16.length; i++) channelData[i] = dataInt16[i] / 32768.0;
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.start();
            }
          },
          onclose: () => setIsConnected(false),
          onerror: () => setIsConnected(false)
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setIsConnected(false);
    }
  };

  useEffect(() => {
    if (isOpen) startCall();
    return () => {
      sessionRef.current?.close();
      audioContextRef.current?.close();
    };
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
      <div className="relative w-full max-w-md bg-gray-900 border border-white/10 rounded-[2.5rem] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-500">
        <div className="absolute top-0 left-0 w-full h-1 bg-indigo-500 animate-pulse"></div>

        <div className="p-12 flex flex-col items-center text-center">
          <div className="relative mb-8">
            <div className={`absolute -inset-4 rounded-full bg-indigo-500/20 animate-ping ${isConnected ? 'opacity-100' : 'opacity-0'}`}></div>
            <img src={contactAvatar} className="w-32 h-32 rounded-full border-4 border-indigo-500 relative z-10 shadow-2xl" alt="" />
            {isConnected && (
              <div className="absolute -bottom-2 -right-2 bg-green-500 p-2 rounded-full border-4 border-gray-900 z-20">
                <div className="w-3 h-3 bg-white rounded-full animate-pulse"></div>
              </div>
            )}
          </div>

          <h3 className="text-2xl font-bold text-white mb-1">{contactName}</h3>
          <p className="text-indigo-400 font-mono text-sm mb-6 uppercase tracking-widest">
            {isConnected ? `VORTEX ENCRYPTED CALL • ${formatTime(callDuration)}` : 'ESTABLISHING QUANTUM LINK...'}
          </p>

          <div className="w-full flex justify-center gap-4 mb-12">
            {[...Array(8)].map((_, i) => (
              <div 
                key={i} 
                className={`w-1 bg-indigo-500 rounded-full transition-all duration-100 ${isConnected ? 'animate-bounce' : 'opacity-20'}`}
                style={{ height: isConnected ? `${Math.random() * 40 + 10}px` : '10px', animationDelay: `${i * 0.1}s` }}
              ></div>
            ))}
          </div>

          <div className="flex items-center gap-6">
            <button 
              onClick={() => setIsMuted(!isMuted)}
              className={`w-16 h-16 rounded-full flex items-center justify-center transition-all ${isMuted ? 'bg-red-500 text-white' : 'bg-white/10 text-white hover:bg-white/20'}`}
            >
              <span className="text-2xl">{isMuted ? '🔇' : '🎤'}</span>
            </button>
            <button 
              onClick={onClose}
              className="w-20 h-20 bg-red-600 hover:bg-red-700 text-white rounded-full flex items-center justify-center shadow-xl shadow-red-600/20 hover:scale-110 active:scale-95 transition-all"
            >
              <span className="text-3xl">🤙</span>
            </button>
            <button className="w-16 h-16 bg-white/10 text-white rounded-full flex items-center justify-center hover:bg-white/20 transition-all">
              <span className="text-2xl">📹</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

