import { useState, useEffect, useCallback } from 'react';
import { User, Project, Message, Theme, AppState } from '../types';

const STORAGE_KEY = 'vortex_data_v2';

const initialUser: User = {
  id: 'u1',
  name: 'Investor Demo',
  email: 'demo@vortex.io',
  avatar: 'https://picsum.photos/seed/vortex/200',
  bio: 'Silicon Valley Visionary | Full Stack Engineer',
  skills: ['React', 'TypeScript', 'Node.js', 'PostgreSQL', 'Python', 'AWS'],
  coins: 45000,
  reputation: 98,
  hasSkillBadge: true
};

export function useVortexState() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch(e) {
        console.error("State parse error", e);
      }
    }
    return {
      currentUser: initialUser,
      projects: [],
      messages: [],
      theme: Theme.DIM
    };
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  // Apply theme to document element
  useEffect(() => {
    const root = document.documentElement;
    const { theme } = state;

    root.classList.remove('dark', 'light', 'dim');
    if (theme === Theme.DIM) {
      root.classList.add('dark', 'dim');
    } else if (theme === Theme.DARK) {
      root.classList.add('dark');
    } else {
      root.classList.add('light');
    }
  }, [state.theme]);

  const setTheme = useCallback((theme: Theme) => {
    setState(prev => ({ ...prev, theme }));
  }, []);

  const addProject = useCallback((project: Project) => {
    setState(prev => ({
      ...prev,
      projects: [project, ...prev.projects],
      currentUser: prev.currentUser ? { ...prev.currentUser, coins: prev.currentUser.coins + 1000 } : null
    }));
  }, []);

  const reactToProject = useCallback((projectId: string, type: 'like' | 'love' | 'laugh' | 'dislike') => {
    setState(prev => {
      const projects = prev.projects.map(p => {
        if (p.id === projectId) {
          return {
            ...p,
            reactions: {
              ...p.reactions,
              [type]: p.reactions[type] + 1
            }
          };
        }
        return p;
      });

      const coinDelta = type === 'dislike' ? -100 : 250;
      return {
        ...prev,
        projects,
        currentUser: prev.currentUser ? { ...prev.currentUser, coins: Math.max(0, prev.currentUser.coins + coinDelta) } : null
      };
    });
  }, []);

  const sendMessage = useCallback((msg: Message) => {
    setState(prev => ({
      ...prev,
      messages: [...prev.messages, msg]
    }));
  }, []);

  return {
    ...state,
    setTheme,
    addProject,
    reactToProject,
    sendMessage
  };
}

