import React, { useState } from 'react';
import { geminiService } from '../services/gemini';
import { AppState, Project } from '../types';

interface AIStarterProps {
  state: AppState;
  onProjectCreated: (p: Project) => void;
}

const AIStarter: React.FC<AIStarterProps> = ({ state, onProjectCreated }) => {
  const [interest, setInterest] = useState('');
  const [loading, setLoading] = useState(false);
  const [suggestion, setSuggestion] = useState<any>(null);
  const { theme } = state;
  const isDark = theme === 'dark' || theme === 'dim';

  const handleGenerate = async () => {
    if (!interest || !state.currentUser) return;
    setLoading(true);
    try {
      const result = await geminiService.generateProjectStarter(state.currentUser.skills, interest);
      setSuggestion(result);
    } catch (e) {
      console.error(e);
      alert('Neural sync failed. Check API key integrity.');
    } finally {
      setLoading(false);
    }
  };

  const handleLaunch = () => {
    if (!suggestion || !state.currentUser) return;
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      ownerId: state.currentUser.id,
      title: suggestion.title,
      description: suggestion.description,
      files: suggestion.starterFiles,
      roadmap: suggestion.roadmap,
      reactions: { like: 0, love: 0, laugh: 0, dislike: 0 },
      isPublic: true,
      createdAt: new Date().toISOString(),
      reputationScore: 0
    };
    onProjectCreated(newProject);
    setSuggestion(null);
    setInterest('');
  };

  return (
    <div className="max-w-7xl mx-auto space-y-24 animate-fade-in py-20 pb-64 perspective-2000">
      {/* Immersive World-Class Header */}
      <div className="text-center relative py-32 overflow-hidden rounded-[6rem] group">
        <div className="absolute inset-0 bg-indigo-600/10 blur-[150px] rounded-full animate-glow-pulse"></div>
        <div className="absolute inset-0 hologram-grid opacity-30 pointer-events-none transition-opacity duration-1000 group-hover:opacity-50"></div>
