        <div className="relative z-10 space-y-12">
          <div className="inline-block px-10 py-4 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-[12px] font-black uppercase tracking-[0.8em] text-indigo-500 animate-slide-up stagger-1 shadow-2xl backdrop-blur-md">
            COGNITIVE BLUEPRINT ENGINE • GENESIS MODIFIED
          </div>
          <h2 className="text-9xl md:text-[12rem] font-black tracking-tighter leading-[0.8] animate-slide-up stagger-2 transition-transform duration-1000 hover:scale-105">
            VORTEX <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-500 via-purple-400 to-indigo-600 animate-pulse" style={{ animationDuration: '3s' }}>GENESIS</span>
          </h2>
          <p className="text-4xl opacity-40 font-medium max-w-5xl mx-auto leading-tight animate-slide-up stagger-3 tracking-tight">
            Manifesting high-fidelity architecture from pure concept. Our neural network synthesizes your roadmap, structure, and starting code.
          </p>
        </div>
      </div>

      {/* Futuristic Input Console */}
      <div className={`relative group p-2 rounded-[6rem] transition-all duration-1000 shadow-4xl animate-slide-up stagger-4 ${isDark ? 'bg-gradient-to-br from-indigo-500/30 via-transparent to-purple-500/30' : 'bg-indigo-100'}`}>
        <div className={`rounded-[5.8rem] p-24 space-y-20 transition-all duration-700 overflow-hidden relative ${isDark ? 'bg-vortex-darkCard' : 'bg-white'}`}>
          <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-transparent via-indigo-500 to-transparent opacity-60 animate-scan"></div>

          <div className="space-y-16 relative z-10">
            <div className="space-y-8">
              <label className="block text-[14px] font-black uppercase tracking-[0.6em] opacity-30 px-6">TRANSMIT INTENTIONALITY</label>
              <div className="relative group/input flex flex-col md:flex-row gap-8">
                <input 
                  type="text" 
                  value={interest}
                  onChange={(e) => setInterest(e.target.value)}
                  placeholder="Describe your architectural vision..."
                  className={`flex-1 px-14 py-12 text-4xl font-black rounded-[4rem] outline-none transition-all border-4 shadow-inner ${isDark ? 'bg-black/60 border-white/5 focus:border-indigo-500/60 text-white placeholder:text-white/10' : 'bg-slate-50 border-slate-100 focus:border-indigo-500 text-slate-900 placeholder:text-slate-300'}`}
                />
                <button 
                  onClick={handleGenerate}
                  disabled={loading || !interest}
                  className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white px-20 py-10 rounded-[4rem] font-black tracking-tighter text-3xl shadow-3xl transition-all flex items-center justify-center gap-6 active:scale-95 group-hover/input:shadow-indigo-500/40 min-w-[350px]"
                >
                  {loading ? (
                      <div className="flex items-center gap-6">
                        <div className="w-10 h-10 border-8 border-white/30 border-t-white rounded-full animate-spin"></div>
                        <span className="animate-pulse">SYNTHESIZING...</span>
                      </div>
                  ) : (
                    <>
                      <span>MANIFEST</span>
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><path d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
