      {/* Manifestation Result Output */}
      {suggestion && (
        <div className="animate-slide-up space-y-20 stagger-1 perspective-2000 pb-40">
          <div className={`rounded-[6rem] p-24 border-4 shadow-5xl transition-all relative overflow-hidden ${isDark ? 'bg-vortex-darkCard border-white/5' : 'bg-white border-slate-100'}`}>
            <div className="absolute -top-64 -right-64 w-[500px] h-[500px] bg-indigo-500/10 rounded-full blur-[120px] animate-glow-pulse"></div>

            <div className="flex flex-col xl:flex-row justify-between items-start gap-24 mb-24">
              <div className="space-y-10 max-w-6xl">
                <div className="inline-flex items-center gap-4 px-8 py-3 bg-green-500/10 text-green-500 rounded-2xl text-[12px] font-black uppercase tracking-[0.4em] border border-green-500/20">
                  <span className="w-3 h-3 bg-green-500 rounded-full animate-ping"></span>
                  SYNTETHIC CORE RESOLVED
                </div>
                <h3 className="text-8xl font-black tracking-tighter leading-none">{suggestion.title}</h3>
                <p className="text-3xl opacity-40 leading-relaxed font-medium tracking-tight">{suggestion.description}</p>
              </div>
              <button 
                onClick={handleLaunch}
                className="bg-green-600 hover:bg-green-700 text-white px-24 py-12 rounded-[3.5rem] font-black tracking-tighter text-4xl shadow-4xl shadow-green-500/40 hover:scale-105 active:scale-95 transition-all w-full xl:w-auto"
              >
                DEPLOY ARCHITECTURE
              </button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-24">
