            THE <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-500 via-purple-500 to-indigo-600">GRID</span>
          </h1>

          <div className="max-w-3xl mx-auto relative group animate-slide-up stagger-3 px-6">
