            <div className={`relative flex items-center p-2 rounded-[2.5rem] border-2 transition-all duration-700 ${isDark ? 'bg-black/70 border-white/10 group-focus-within:border-indigo-500/60' : 'bg-white border-slate-200 group-focus-within:border-indigo-500'}`}>
              <div className="pl-8 text-2xl opacity-40">🔍</div>
              <input 
                type="text" 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder={mode === 'Projects' ? "Synchronize with patterns..." : "Search Architects & Creators..."}
                className="flex-1 bg-transparent border-none px-6 py-5 text-2xl font-black outline-none placeholder:opacity-20 tracking-tight"
              />
              <div className="hidden sm:flex gap-2 pr-6">
                <span className={`px-4 py-2 rounded-xl text-[10px] font-black border tracking-widest ${isDark ? 'bg-white/5 border-white/10 text-white/40' : 'bg-slate-100 border-slate-200 text-slate-400'}`}>⌘ K</span>
