export function useVortexState() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        return parsed;
      } catch(e) {
        console.error("State parse error", e);
      }
    }
    return {
      currentUser: initialUsers[0],
      users: initialUsers,
      projects: demoProjects,
      messages: [],
      theme: Theme.DARK,
      subscriptionEvents: initialSubscriptionEvents
    };
  });

  useEffect(() => {
    const checkExpiration = () => {
      setState(prev => {
        if (!prev.currentUser?.isPrime || !prev.currentUser.primeUntil) return prev;
        const now = new Date();
        const expiration = new Date(prev.currentUser.primeUntil);
        if (now > expiration) {
          const updatedUser = { ...prev.currentUser, isPrime: false, primeUntil: null };
          return {
            ...prev,
            currentUser: updatedUser,
            users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u)
          };
        }
        return prev;
      });
    };
    const timer = setInterval(checkExpiration, 60000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  useEffect(() => {
    const root = document.documentElement;
    const { theme } = state;
    root.classList.remove('light', 'dark', 'dim');
    if (theme === Theme.DIM) {
      root.classList.add('dark', 'dim');
    } else if (theme === Theme.DARK) {
      root.classList.add('dark');
    } else {
      root.classList.add('light');
    }
  }, [state.theme]);

  const setTheme = useCallback((theme: Theme) => {
    setState(prev => ({ ...prev, theme }));
  }, []);

  const addProject = useCallback((project: Project) => {
    setState(prev => ({
      ...prev,
      projects: [project, ...prev.projects],
      currentUser: prev.currentUser ? { ...prev.currentUser, coins: prev.currentUser.coins + 1500 } : null
    }));
  }, []);

  const reactToProject = useCallback((projectId: string, type: 'like' | 'love' | 'laugh' | 'dislike') => {
    setState(prev => {
      const projects = prev.projects.map(p => {
        if (p.id === projectId) {
          return { ...p, reactions: { ...p.reactions, [type]: p.reactions[type] + 1 } };
        }
        return p;
      });
      const coinDelta = type === 'dislike' ? -200 : 400;
      return {
        ...prev,
        projects,
        currentUser: prev.currentUser ? { ...prev.currentUser, coins: Math.max(0, prev.currentUser.coins + coinDelta) } : null
      };
    });
  }, []);

  const toggleFollow = useCallback((targetUserId: string) => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const isFollowing = prev.currentUser.following.includes(targetUserId);
      const updatedFollowing = isFollowing 
        ? prev.currentUser.following.filter(id => id !== targetUserId)
        : [...prev.currentUser.following, targetUserId];
      const updatedCurrentUser = { ...prev.currentUser, following: updatedFollowing };
      const updatedUsers = prev.users.map(u => {
        if (u.id === targetUserId) {
          const updatedFollowers = isFollowing
            ? u.followers.filter(id => id !== prev.currentUser!.id)
            : [...u.followers, prev.currentUser!.id];
          return { ...u, followers: updatedFollowers };
        }
        if (u.id === prev.currentUser!.id) return updatedCurrentUser;
        return u;
      });
      return { ...prev, currentUser: updatedCurrentUser, users: updatedUsers };
    });
  }, []);

  const sendMessage = useCallback((msg: Message) => {
    setState(prev => ({ ...prev, messages: [...prev.messages, msg] }));
  }, []);

  const toggleProfilePrivacy = useCallback(() => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const newPrivacy = !prev.currentUser.isPrivate;
      const updatedUser = { ...prev.currentUser, isPrivate: newPrivacy };
      return {
        ...prev,
        currentUser: updatedUser,
        users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u)
      };
    });
  }, []);

  const purchasePrime = useCallback((cost: number) => {
    setState(prev => {
      if (!prev.currentUser || prev.currentUser.coins < cost) return prev;
      const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
      const expiryDate = new Date(Date.now() + sevenDaysInMs).toISOString();
      const updatedUser = { ...prev.currentUser, coins: prev.currentUser.coins - cost, isPrime: true, primeUntil: expiryDate };
      const newEvent: SubscriptionEvent = {
        id: Math.random().toString(36).substr(2, 9),
        userName: updatedUser.name,
        userAvatar: updatedUser.avatar,
        tierName: '7-Day Protocol',
        timestamp: new Date().toISOString()
      };
      return {
        ...prev,
        currentUser: updatedUser,
        users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u),
        subscriptionEvents: [newEvent, ...prev.subscriptionEvents].slice(0, 10)
      };
    });
  }, []);

  const activatePrimeDirectly = useCallback((days: number, tierLabel: string) => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const durationInMs = days * 24 * 60 * 60 * 1000;
      const expiryDate = new Date(Date.now() + durationInMs).toISOString();
      const updatedUser = { ...prev.currentUser, isPrime: true, primeUntil: expiryDate };
      const newEvent: SubscriptionEvent = {
        id: Math.random().toString(36).substr(2, 9),
        userName: updatedUser.name,
        userAvatar: updatedUser.avatar,
        tierName: tierLabel,
        timestamp: new Date().toISOString()
      };
      return {
        ...prev,
        currentUser: updatedUser,
        users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u),
        subscriptionEvents: [newEvent, ...prev.subscriptionEvents].slice(0, 10)
      };
    });
  }, []);

  return {
    ...state,
    setTheme,
    addProject,
    reactToProject,
    sendMessage,
    toggleFollow,
    toggleProfilePrivacy,
    purchasePrime,
    activatePrimeDirectly
  };
}

