interface ChatProps {
  state: AppState;
  onSendMessage: (msg: Message) => void;
  onViewProfile?: (userId: string) => void;
}

const DEMO_CONTACTS = [
  { id: 'u2', name: 'Sarah Developer', avatar: 'https://picsum.photos/seed/sarah/40', status: 'online' },
  { id: 'u3', name: 'James HR', avatar: 'https://picsum.photos/seed/james/40', status: 'offline' },
  { id: 'u4', name: 'Vector AI', avatar: 'https://picsum.photos/seed/ai/40', status: 'online' },
];

