import React, { useMemo } from 'react';
import { AppState, Project } from '../types';

interface DashboardProps {
  state: AppState;
}

const Dashboard: React.FC<DashboardProps> = ({ state }) => {
  const { currentUser, projects, theme } = state;
  const isDark = theme === 'dark' || theme === 'dim';

  const greeting = useMemo(() => {
    const hour = new Date().getHours();
    // 5 AM - 12 PM: Morning Investor
    if (hour >= 5 && hour < 12) return "Good Morning, Investor";
    // 12 PM - 6 PM: Afternoon Architect
    if (hour >= 12 && hour < 18) return "Good Afternoon, Architect";
    // 6 PM - 10 PM: Evening Creator
    if (hour >= 18 && hour < 22) return "Good Evening, Creator";
    // 10 PM - 5 AM: Night Hunter/Owl
    return "Greetings, Night Hunter";
  }, []);

  const subtitle = useMemo(() => {
    const hour = new Date().getHours();
    if (hour >= 5 && hour < 12) return "The markets are waking up. Time to manifest new capital.";
    if (hour >= 22 || hour < 5) return "While the world sleeps, the elite build the future.";
    return "The mesh is active and synchronized.";
  }, []);

  const trendingProjects = useMemo(() => {
    return [...projects]
      .sort((a, b) => {
        const scoreA = (a.reactions.love * 3) + (a.reactions.like * 1) - (a.reactions.dislike * 2);
        const scoreB = (b.reactions.love * 3) + (b.reactions.like * 1) - (b.reactions.dislike * 2);
        return scoreB - scoreA;
      })
      .slice(0, 4);
  }, [projects]);

  return (
    <div className="space-y-24 animate-fade-in perspective-2000 pb-32">
      {/* Cinematic Hero Greeting */}
      <section className="relative overflow-hidden rounded-[5rem] p-20 bg-gradient-to-br from-indigo-950 via-indigo-900 to-purple-950 text-white shadow-3xl group transition-all duration-1000 hover:shadow-indigo-500/40">
        <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-indigo-500/10 rounded-full blur-[150px] -mr-64 -mt-64 animate-glow-pulse"></div>
        <div className="absolute inset-0 hologram-grid opacity-20 pointer-events-none"></div>
