import React, { useState } from 'react';
import { Project, ExternalLink, ProjectFile } from '../types';

interface ProjectListProps {
  projects: Project[];
  onReact: (id: string, type: 'like' | 'love' | 'laugh' | 'dislike') => void;
  onAddProject?: (p: Project) => void;
  currentUser?: any;
  isDark?: boolean;
}

const ProjectList: React.FC<ProjectListProps> = ({ projects, onReact, onAddProject, currentUser, isDark = true }) => {
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [isDragging, setIsDragging] = useState(false);
  const [showNewBuildModal, setShowNewBuildModal] = useState(false);

  // New Build Form State
  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newUrl, setNewUrl] = useState('');
  const [newUrlLabel, setNewUrlLabel] = useState('');
  const [urlType, setUrlType] = useState<'github' | 'drive' | 'generic' | 'figma'>('generic');

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = () => {
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const files = Array.from(e.dataTransfer.files);
    if (files.length > 0) {
      setNewTitle(files[0].name.split('.')[0].toUpperCase() + "_DEPLOY");
      setNewDesc(`Injected payload from file: ${files[0].name}. Architectural parity verified by VORTEX engine.`);
      setShowNewBuildModal(true);
    }
  };

  const handleDeploy = () => {
    if (!newTitle || !currentUser) return;

    const links: ExternalLink[] = [];
    if (newUrl) {
      links.push({
        label: newUrlLabel || 'Primary Resource',
        url: newUrl,
        type: urlType
      });
    }

    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      ownerId: currentUser.id,
      title: newTitle,
      description: newDesc,
      files: [], // In a real app, file contents would be processed here
      externalLinks: links,
      roadmap: ['Core Initialization', 'Pattern Analysis', 'Public Manifestation'],
      reactions: { like: 0, love: 0, laugh: 0, dislike: 0 },
      isPublic: true,
      createdAt: new Date().toISOString(),
      reputationScore: 0
    };

    onAddProject?.(newProject);
    setShowNewBuildModal(false);
    resetForm();
  };

  const resetForm = () => {
    setNewTitle('');
    setNewDesc('');
    setNewUrl('');
    setNewUrlLabel('');
    setUrlType('generic');
  };

  return (
    <div 
      className="space-y-12 animate-fade-in pb-32 min-h-screen"
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      {/* View Controls Header */}
