export enum Theme {
  LIGHT = 'light',
  DARK = 'dark',
  DIM = 'dim'
}

export enum AccountType {
  PERSONAL = 'Personal',
  PROFESSIONAL = 'Professional'
}

export interface User {
  id: string;
  name: string;
  email: string;
  avatar: string;
  bio: string;
  skills: string[];
  coins: number;
  reputation: number;
  hasSkillBadge: boolean;
  followers: string[]; // User IDs
  following: string[]; // User IDs
  accountType: AccountType;
  isPrivate: boolean;
  isPrime: boolean;
  primeUntil: string | null; // Timestamp for subscription expiration
  starredUsers: string[]; // List of user IDs starred by this user
  nicknames: Record<string, string>; // Map of userID -> custom nickname
}

export interface ProjectFile {
  name: string;
  content: string;
  language: string;
}

export interface ExternalLink {
  label: string;
  url: string;
  type: 'github' | 'drive' | 'generic' | 'figma';
}

export interface Project {
  id: string;
  ownerId: string;
  title: string;
  description: string;
  files: ProjectFile[];
  externalLinks: ExternalLink[];
  roadmap: string[];
  reactions: {
    like: number;
    love: number;
    laugh: number;
    dislike: number;
  };
  isPublic: boolean;
  createdAt: string;
  reputationScore: number;
}

export interface Message {
  id: string;
  senderId: string;
  receiverId: string;
  content: string;
  timestamp: string;
}

export interface SubscriptionEvent {
  id: string;
  userName: string;
  userAvatar: string;
  tierName: string;
  timestamp: string;
}

export interface AppState {
  currentUser: User | null;
  users: User[];
  projects: Project[];
  messages: Message[];
  theme: Theme;
  subscriptionEvents: SubscriptionEvent[]; // Track recent upgrades
}

