export function useVortexState() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        return parsed;
      } catch(e) {
        console.error("State parse error", e);
      }
    }
    return {
      currentUser: initialUsers[0],
      users: initialUsers,
      projects: demoProjects,
      messages: [],
      theme: Theme.DARK,
      subscriptionEvents: initialSubscriptionEvents
    };
  });

  useEffect(() => {
    const checkExpiration = () => {
      setState(prev => {
        if (!prev.currentUser?.isPrime || !prev.currentUser.primeUntil) return prev;
        const now = new Date();
        const expiration = new Date(prev.currentUser.primeUntil);
        if (now > expiration) {
          const updatedUser = { ...prev.currentUser, isPrime: false, primeUntil: null };
          return {
            ...prev,
            currentUser: updatedUser,
            users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u)
          };
        }
        return prev;
      });
    };
    const timer = setInterval(checkExpiration, 60000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  useEffect(() => {
    const root = document.documentElement;
    const { theme } = state;
    root.classList.remove('light', 'dark', 'dim');
    if (theme === Theme.DIM) {
      root.classList.add('dark', 'dim');
    } else if (theme === Theme.DARK) {
      root.classList.add('dark');
    } else {
      root.classList.add('light');
    }
  }, [state.theme]);

  const setTheme = useCallback((theme: Theme) => {
    setState(prev => ({ ...prev, theme }));
  }, []);

  const addProject = useCallback((project: Project) => {
    setState(prev => ({
      ...prev,
      projects: [project, ...prev.projects],
      currentUser: prev.currentUser ? { ...prev.currentUser, coins: prev.currentUser.coins + 1500 } : null
    }));
  }, []);

  const reactToProject = useCallback((projectId: string, type: 'like' | 'love' | 'laugh' | 'dislike') => {
    setState(prev => {
      const projects = prev.projects.map(p => {
        if (p.id === projectId) {
          return { ...p, reactions: { ...p.reactions, [type]: p.reactions[type] + 1 } };
        }
        return p;
      });
      const coinDelta = type === 'dislike' ? -200 : 400;
      return {
        ...prev,
        projects,
        currentUser: prev.currentUser ? { ...prev.currentUser, coins: Math.max(0, prev.currentUser.coins + coinDelta) } : null
      };
    });
  }, []);

  const toggleFollow = useCallback((targetUserId: string) => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const isFollowing = prev.currentUser.following.includes(targetUserId);
      const updatedFollowing = isFollowing 
        ? prev.currentUser.following.filter(id => id !== targetUserId)
        : [...prev.currentUser.following, targetUserId];
      const updatedCurrentUser = { ...prev.currentUser, following: updatedFollowing };
      const updatedUsers = prev.users.map(u => {
        if (u.id === targetUserId) {
          const updatedFollowers = isFollowing
            ? u.followers.filter(id => id !== prev.currentUser!.id)
            : [...u.followers, prev.currentUser!.id];
          return { ...u, followers: updatedFollowers };
        }
        if (u.id === prev.currentUser!.id) return updatedCurrentUser;
        return u;
      });
      return { ...prev, currentUser: updatedCurrentUser, users: updatedUsers };
    });
  }, []);

  const sendMessage = useCallback((msg: Message) => {
    setState(prev => ({ ...prev, messages: [...prev.messages, msg] }));
  }, []);

  const toggleProfilePrivacy = useCallback(() => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const newPrivacy = !prev.currentUser.isPrivate;
      const updatedUser = { ...prev.currentUser, isPrivate: newPrivacy };
      return {
        ...prev,
        currentUser: updatedUser,
        users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u)
      };
    });
  }, []);

  const toggleStarUser = useCallback((targetUserId: string) => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const isStarred = prev.currentUser.starredUsers.includes(targetUserId);
      const updatedStarred = isStarred
        ? prev.currentUser.starredUsers.filter(id => id !== targetUserId)
        : [...prev.currentUser.starredUsers, targetUserId];
      const updatedUser = { ...prev.currentUser, starredUsers: updatedStarred };
      return {
        ...prev,
        currentUser: updatedUser,
        users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u)
      };
    });
  }, []);

  const setUserNickname = useCallback((targetUserId: string, nickname: string) => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const updatedNicknames = { ...prev.currentUser.nicknames, [targetUserId]: nickname };
      const updatedUser = { ...prev.currentUser, nicknames: updatedNicknames };
      return {
        ...prev,
        currentUser: updatedUser,
        users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u)
      };
    });
  }, []);

  const purchasePrime = useCallback((cost: number) => {
    setState(prev => {
      if (!prev.currentUser || prev.currentUser.coins < cost) return prev;
      const sevenDaysInMs = 7 * 24 * 60 * 60 * 1000;
      const expiryDate = new Date(Date.now() + sevenDaysInMs).toISOString();
      const updatedUser = { ...prev.currentUser, coins: prev.currentUser.coins - cost, isPrime: true, primeUntil: expiryDate };
      const newEvent: SubscriptionEvent = {
        id: Math.random().toString(36).substr(2, 9),
        userName: updatedUser.name,
        userAvatar: updatedUser.avatar,
        tierName: '7-Day Protocol',
        timestamp: new Date().toISOString()
      };
      return {
        ...prev,
        currentUser: updatedUser,
        users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u),
        subscriptionEvents: [newEvent, ...prev.subscriptionEvents].slice(0, 10)
      };
    });
  }, []);

  const activatePrimeDirectly = useCallback((days: number, tierLabel: string) => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const durationInMs = days * 24 * 60 * 60 * 1000;
      const expiryDate = new Date(Date.now() + durationInMs).toISOString();
      const updatedUser = { ...prev.currentUser, isPrime: true, primeUntil: expiryDate };
      const newEvent: SubscriptionEvent = {
        id: Math.random().toString(36).substr(2, 9),
        userName: updatedUser.name,
        userAvatar: updatedUser.avatar,
        tierName: tierLabel,
        timestamp: new Date().toISOString()
      };
      return {
        ...prev,
        currentUser: updatedUser,
        users: prev.users.map(u => u.id === updatedUser.id ? updatedUser : u),
        subscriptionEvents: [newEvent, ...prev.subscriptionEvents].slice(0, 10)
      };
    });
  }, []);

  return {
    ...state,
    setTheme,
    addProject,
    reactToProject,
    sendMessage,
    toggleFollow,
    toggleProfilePrivacy,
    toggleStarUser,
    setUserNickname,
    purchasePrime,
    activatePrimeDirectly
  };
}

import React, { useState, useMemo } from 'react';
import { AppState, Message, User } from '../types';
import CallingUI from './CallingUI';

interface ChatProps {
  state: AppState & { 
    toggleStarUser: (id: string) => void;
    setUserNickname: (id: string, name: string) => void;
  };
  onSendMessage: (msg: Message) => void;
  onViewProfile?: (userId: string) => void;
}

const Chat: React.FC<ChatProps> = ({ state, onSendMessage, onViewProfile }) => {
  const { currentUser, theme, users, toggleStarUser, setUserNickname } = state;
  const isDark = theme === 'dark' || theme === 'dim';

  // Contacts are everyone except current user
  const contacts = useMemo(() => {
    return users.filter(u => u.id !== currentUser?.id).map(u => ({
      ...u,
      nickname: currentUser?.nicknames?.[u.id] || u.name,
      isStarred: currentUser?.starredUsers?.includes(u.id) || false
    })).sort((a, b) => {
      // Starred first, then by name
      if (a.isStarred && !b.isStarred) return -1;
      if (!a.isStarred && b.isStarred) return 1;
      return a.nickname.localeCompare(b.nickname);
    });
  }, [users, currentUser]);

  const [selectedContactId, setSelectedContactId] = useState(contacts[0]?.id);
  const selectedContact = contacts.find(c => c.id === selectedContactId) || contacts[0];

  const [text, setText] = useState('');
  const [isCalling, setIsCalling] = useState(false);
  const [isEditingNickname, setIsEditingNickname] = useState(false);
  const [tempNickname, setTempNickname] = useState('');

  const chatMessages = state.messages.filter(m => 
    (m.senderId === state.currentUser?.id && m.receiverId === selectedContactId) ||
    (m.senderId === selectedContactId && m.receiverId === state.currentUser?.id)
  );

  const handleSend = () => {
    if (!text.trim() || !state.currentUser || !selectedContactId) return;
    const newMsg: Message = {
      id: Math.random().toString(),
      senderId: state.currentUser.id,
      receiverId: selectedContactId,
      content: text,
      timestamp: new Date().toISOString()
    };
    onSendMessage(newMsg);
    setText('');
  };

  const handleSaveNickname = () => {
    if (selectedContactId) {
      setUserNickname(selectedContactId, tempNickname);
      setIsEditingNickname(false);
    }
  };

  return (
    <div className={`flex h-[calc(100vh-180px)] rounded-[3rem] overflow-hidden border shadow-2xl animate-fade-in ${isDark ? 'bg-vortex-darkCard border-vortex-darkBorder' : 'bg-white border-slate-200'}`}>
      <CallingUI 
        isOpen={isCalling} 
        onClose={() => setIsCalling(false)} 
        contactName={selectedContact?.nickname || selectedContact?.name} 
        contactAvatar={selectedContact?.avatar} 
      />

      {/* Sidebar */}
      <div className={`w-80 border-r flex flex-col transition-all duration-700 ${isDark ? 'bg-black/40 border-vortex-darkBorder' : 'bg-slate-50/50 border-slate-200'}`}>
        <div className="p-8">
          <h2 className="text-2xl font-black tracking-tighter mb-6 uppercase">Sync Nodes</h2>
          <div className="relative">
            <input 
              type="text" 
              placeholder="Locate node..." 
              className={`w-full pl-12 pr-4 py-4 rounded-2xl text-sm outline-none transition-all ${isDark ? 'bg-black/50 border-white/5 focus:border-indigo-500/50' : 'bg-white border-slate-200 focus:border-indigo-500'}`}
            />
            <span className="absolute left-4 top-4 opacity-30">🔍</span>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto px-4 pb-4 space-y-2 custom-scrollbar">
          {contacts.map(c => {
            const isActive = selectedContactId === c.id;
            return (
              <div key={c.id} className="relative group/contact">
                <button 
                  onClick={() => setSelectedContactId(c.id)}
                  className={`w-full p-4 flex items-center gap-4 rounded-[1.5rem] transition-all duration-500 ${isActive ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/20 scale-[1.02]' : `hover:bg-indigo-500/5 ${isDark ? 'text-slate-400' : 'text-slate-600'}`}`}
                >
                  <div className="relative flex-shrink-0">
                    <img src={c.avatar} className="w-12 h-12 rounded-2xl object-cover" alt="" />
                    <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 border-4 border-white dark:border-black rounded-full"></div>
                  </div>
                  <div className="text-left overflow-hidden flex-1">
                    <p className={`font-black text-sm tracking-tight truncate ${isActive ? 'text-white' : ''}`}>
                      {c.isStarred && <span className="mr-1 text-yellow-500">★</span>}
                      {c.nickname}
                    </p>
                    <p className={`text-[10px] font-medium truncate w-full mt-0.5 opacity-50 uppercase tracking-widest ${isActive ? 'text-indigo-100' : ''}`}>Active link...</p>
                  </div>
                </button>
                <button 
                  onClick={(e) => { e.stopPropagation(); toggleStarUser(c.id); }}
                  className={`absolute right-6 top-1/2 -translate-y-1/2 opacity-0 group-hover/contact:opacity-100 transition-opacity text-lg ${c.isStarred ? 'text-yellow-500 opacity-100' : 'text-slate-400 hover:text-yellow-500'}`}
                >
                  {c.isStarred ? '★' : '☆'}
                </button>
              </div>
            );
          })}
        </div>
      </div>

      {/* Main Chat Area */}
      <div className="flex-1 flex flex-col relative overflow-hidden">
        <div className={`p-8 border-b flex items-center justify-between z-10 ${isDark ? 'bg-vortex-darkCard border-vortex-darkBorder' : 'bg-white border-slate-200'}`}>
          <div className="flex items-center gap-5">
            <div className="relative cursor-pointer group" onClick={() => onViewProfile?.(selectedContact?.id)}>
              <div className="absolute -inset-1 bg-indigo-500 rounded-2xl blur opacity-0 group-hover:opacity-40 transition-opacity"></div>
              <img src={selectedContact?.avatar} className="w-14 h-14 rounded-2xl shadow-xl shadow-indigo-500/10 relative z-10" alt="" />
              <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 border-4 border-white dark:border-black rounded-full shadow-[0_0_10px_rgba(34,197,94,0.5)] z-20"></div>
            </div>
            <div>
              <div className="flex items-center gap-3">
                <p className="font-black text-xl tracking-tight cursor-pointer hover:text-indigo-500 transition-colors" onClick={() => onViewProfile?.(selectedContact?.id)}>
                  {selectedContact?.nickname}
                </p>
                <button 
                  onClick={() => { setTempNickname(selectedContact?.nickname || ''); setIsEditingNickname(true); }}
                  className="text-[10px] font-black uppercase tracking-widest opacity-30 hover:opacity-100 hover:text-indigo-500 transition-all"
                >
                  [EDIT NICKNAME]
                </button>
                <button 
                  onClick={() => toggleStarUser(selectedContact?.id)}
                  className={`text-xl transition-all ${selectedContact?.isStarred ? 'text-yellow-500 scale-125' : 'text-slate-300 hover:text-yellow-500'}`}
                >
                  {selectedContact?.isStarred ? '★' : '☆'}
                </button>
              </div>
              <div className="flex items-center gap-2 mt-0.5">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.4)]"></span>
                <p className="text-[10px] font-black uppercase tracking-[0.2em] text-green-500">Quantum Parity Established</p>
              </div>
            </div>
          </div>
          <div className="flex gap-3">
            <button 
              onClick={() => setIsCalling(true)}
              className="w-14 h-14 bg-indigo-500/10 text-indigo-500 rounded-2xl flex items-center justify-center hover:bg-indigo-600 hover:text-white transition-all shadow-sm group"
            >
              <span className="text-2xl group-hover:scale-110 transition-transform">📞</span>
            </button>
            <button className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-all shadow-sm group ${isDark ? 'bg-white/5 hover:bg-white/10' : 'bg-slate-100 hover:bg-slate-200'}`}>
              <span className="text-2xl group-hover:scale-110 transition-transform">📹</span>
            </button>
          </div>
        </div>

        {/* Nickname Editor Overlay */}
        {isEditingNickname && (
          <div className="absolute inset-x-0 top-32 z-20 px-10 animate-slide-up">
            <div className={`p-6 rounded-[2rem] border-2 shadow-4xl flex items-center gap-4 ${isDark ? 'bg-vortex-darkCard border-indigo-500/30' : 'bg-white border-indigo-500'}`}>
              <input 
                type="text" 
                value={tempNickname}
                onChange={(e) => setTempNickname(e.target.value)}
                placeholder="Assign brief nickname..."
                className="flex-1 bg-transparent border-none outline-none font-black text-lg tracking-tight px-4"
                autoFocus
                onKeyDown={(e) => e.key === 'Enter' && handleSaveNickname()}
              />
              <button 
                onClick={handleSaveNickname}
                className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest shadow-lg active:scale-95"
              >
                SAVE ID
              </button>
              <button 
                onClick={() => setIsEditingNickname(false)}
                className="text-xs font-black uppercase tracking-widest opacity-40 hover:opacity-100"
              >
                CANCEL
              </button>
            </div>
          </div>
        )}

        <div className={`flex-1 overflow-y-auto p-10 space-y-8 custom-scrollbar ${isDark ? 'bg-black/20' : 'bg-slate-50/20'}`}>
          {!selectedContactId && (
            <div className="flex flex-col items-center justify-center h-full opacity-10 animate-fade-in">
              <span className="text-9xl mb-6">🛸</span>
              <p className="font-black uppercase tracking-[0.5em] text-sm">Waiting for first contact</p>
            </div>
          )}
          {chatMessages.map(m => {
            const isMe = m.senderId === state.currentUser?.id;
            return (
              <div key={m.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-slide-up`}>
                <div className={`max-w-[70%] p-6 rounded-[2.5rem] text-sm leading-relaxed shadow-xl ${
                  isMe 
                    ? 'bg-indigo-600 text-white rounded-br-none shadow-indigo-500/20' 
                    : `${isDark ? 'bg-vortex-darkCard border-vortex-darkBorder' : 'bg-white border-slate-100'} rounded-bl-none`
                }`}>
                  <p className="font-medium text-base">{m.content}</p>
                  <p className={`text-[9px] font-black mt-3 uppercase tracking-[0.2em] ${isMe ? 'text-indigo-200' : 'opacity-20'}`}>
                    {new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} • Sync Confirmed
                  </p>
                </div>
              </div>
            );
          })}
        </div>

        <div className={`p-8 border-t z-10 ${isDark ? 'bg-vortex-darkCard border-vortex-darkBorder' : 'bg-white border-slate-200'}`}>
          <div className={`flex gap-4 items-center p-3 rounded-[2rem] border shadow-2xl transition-all ${isDark ? 'bg-black/40 border-white/5 focus-within:border-indigo-500/50' : 'bg-slate-50 border-slate-200 focus-within:border-indigo-500'}`}>
            <button className="w-14 h-14 flex items-center justify-center text-2xl opacity-30 hover:opacity-100 transition-opacity">📎</button>
            <input 
              type="text" 
              value={text}
              onChange={(e) => setText(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Inject payload here..."
              className="flex-1 bg-transparent border-none px-6 py-4 text-base focus:ring-0 outline-none font-medium"
            />
            <button 
              onClick={handleSend}
              className="bg-indigo-600 hover:bg-indigo-700 text-white h-14 px-10 rounded-[1.5rem] shadow-2xl shadow-indigo-600/40 transition-all font-black tracking-tight flex items-center gap-3 active:scale-95"
            >
              <span>SEND</span>
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Chat;

import React, { useState } from 'react';
import { useVortexState } from './hooks/useVortexState';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProjectList from './components/ProjectList';
import Discovery from './components/Discovery';
import AIStarter from './components/AIStarter';
import Chat from './components/Chat';
import CallingUI from './components/CallingUI';
import UserProfile from './components/UserProfile';
import Subscription from './components/Subscription';

const App: React.FC = () => {
  const vortex = useVortexState();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewingUserId, setViewingUserId] = useState<string | null>(null);
  const [isAssistantCallOpen, setIsAssistantCallOpen] = useState(false);

  const handleViewProfile = (userId: string) => {
    setViewingUserId(userId);
    setActiveTab('profile');
  };

  const handleMessage = (userId: string) => {
    setActiveTab('chat');
  };

  const handleTalkToAssistant = () => {
    setIsAssistantCallOpen(true);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard state={vortex} />;
      case 'discovery':
        return (
          <Discovery 
            state={vortex} 
            onReact={vortex.reactToProject} 
            onFollow={vortex.toggleFollow} 
            onViewProfile={handleViewProfile}
          />
        );
      case 'projects':
        const myProjects = vortex.projects.filter(p => p.ownerId === vortex.currentUser?.id);
        return (
          <ProjectList 
            projects={myProjects} 
            onReact={vortex.reactToProject} 
            onAddProject={vortex.addProject} 
            currentUser={vortex.currentUser}
            isDark={vortex.theme !== 'light'}
          />
        );
      case 'ai-starter':
        return <AIStarter state={vortex} onProjectCreated={vortex.addProject} />;
      case 'chat':
        return (
          <Chat 
            state={{
              ...vortex,
              toggleStarUser: vortex.toggleStarUser,
              setUserNickname: vortex.setUserNickname
            }} 
            onSendMessage={vortex.sendMessage} 
            onViewProfile={handleViewProfile} 
          />
        );
      case 'subscription':
        return <Subscription state={vortex} onPurchase={vortex.purchasePrime} onActivateDirectly={vortex.activatePrimeDirectly} />;
      case 'profile':
        const displayUser = viewingUserId 
          ? vortex.users.find(u => u.id === viewingUserId) 
          : vortex.currentUser;

        if (!displayUser) return (
          <div className="flex items-center justify-center h-full text-center p-20 opacity-20">
            <div>
              <span className="text-9xl mb-10 block">📡</span>
              <p className="text-xl font-black uppercase tracking_widest">Architect Signal Lost</p>
              <button onClick={() => setActiveTab('dashboard')} className="mt-8 px-10 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest">Return to Base</button>
            </div>
          </div>
        );

        const userProjects = vortex.projects.filter(p => p.ownerId === displayUser.id);
        const isSelf = vortex.currentUser?.id === displayUser.id;
        const isFollowing = vortex.currentUser?.following.includes(displayUser.id) || false;

        return (
          <>
            <UserProfile 
              user={displayUser}
              isSelf={isSelf}
              isFollowing={isFollowing}
              onFollow={vortex.toggleFollow}
              onMessage={handleMessage}
              onTalkToAssistant={handleTalkToAssistant}
              onTogglePrivacy={vortex.toggleProfilePrivacy}
              projects={userProjects}
              isDark={vortex.theme !== 'light'}
              allUsers={vortex.users}
            />

            {!isSelf && (
              <div className="fixed bottom-12 left-1/2 -translate-x-1/2 z-40 animate-slide-up">
                <button 
                  onClick={() => setViewingUserId(null)}
                  className="bg-black/80 backdrop-blur-md text-white px-10 py-5 rounded-full font-black text-xs uppercase tracking-[0.3em] border border-white/20 shadow-4xl hover:bg-indigo-600 transition-all hover:scale-105 active:scale-95"
                >
                  Return to my Identity
                </button>
              </div>
            )}

            <CallingUI 
              isOpen={isAssistantCallOpen} 
              onClose={() => setIsAssistantCallOpen(false)} 
              contactName={displayUser.name + " Assistant"} 
              contactAvatar={displayUser.avatar}
            />
          </>
        );
      default:
        return <Dashboard state={vortex} />;
    }
  };

  const handleTabChange = (tab: string) => {
    if (tab !== 'profile') setViewingUserId(null);
    setActiveTab(tab);
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={handleTabChange} 
      theme={vortex.theme} 
      setTheme={vortex.setTheme}
      user={vortex.currentUser}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

