import React from 'react';
import { RankTier } from './types';

export const MULTIPLIERS = [
  { threshold: 100000, value: 2.5 },
  { threshold: 50000, value: 2.0 },
  { threshold: 10000, value: 1.1 },
  { threshold: 5000, value: 1.0 }
];

export interface RankDef {
  tier: RankTier;
  color: string;
  bg: string;
  icon: string;
  minScore: number; // Weighted score: (coins/1000) + reputation + (projects*2)
}

export const RANK_METRICS: RankDef[] = [
  { tier: 'Grandmaster', icon: '🌌', minScore: 1000, color: 'text-white', bg: 'bg-gradient-to-r from-purple-600 via-pink-500 to-indigo-600' },
  { tier: 'Master', icon: '🔴', minScore: 500, color: 'text-red-500', bg: 'bg-red-500/10 border-red-500/20' },
  { tier: 'Elite', icon: '🟣', minScore: 250, color: 'text-purple-500', bg: 'bg-purple-500/10 border-purple-500/20' },
  { tier: 'Diamond', icon: '💎', minScore: 150, color: 'text-blue-400', bg: 'bg-blue-400/10 border-blue-400/20' },
  { tier: 'Platinum', icon: '💠', minScore: 80, color: 'text-teal-400', bg: 'bg-teal-400/10 border-teal-400/20' },
  { tier: 'Gold', icon: '🟡', minScore: 40, color: 'text-yellow-500', bg: 'bg-yellow-500/10 border-yellow-500/20' },
  { tier: 'Silver', icon: '⚪', minScore: 15, color: 'text-slate-400', bg: 'bg-slate-400/10 border-slate-400/20' },
  { tier: 'Drone', icon: '🤖', minScore: 0, color: 'text-gray-500', bg: 'bg-gray-500/10 border-gray-500/20' },
];

export const calculateUserRank = (user: { coins: number, reputation: number }, projectCount: number): RankTier => {
  const score = (user.coins / 1000) + user.reputation + (projectCount * 2);
  const matched = RANK_METRICS.find(r => score >= r.minScore);
  return matched ? matched.tier : 'Drone';
};

