          {user.name}
        </h3>
        <p className="text-[10px] font-black uppercase tracking-[0.2em] opacity-40 mb-4">{user.followers.length} Followers</p>

        <p className="text-xs opacity-50 mb-6 line-clamp-2 leading-relaxed px-2">"{user.bio}"</p>

        <div className="mt-auto w-full">
           {!isSelf ? (
             <button 
