import React, { useState, useMemo } from 'react';
import { AppState, Project, User, AccountType } from '../types';
import { RANK_METRICS } from '../constants';

interface DiscoveryProps {
  state: AppState;
  onReact: (id: string, type: 'like' | 'love' | 'laugh' | 'dislike') => void;
  onFollow: (id: string) => void;
  onViewProfile?: (userId: string) => void;
}

const Discovery: React.FC<DiscoveryProps> = ({ state, onReact, onFollow, onViewProfile }) => {
  const { projects, users, currentUser, theme } = state;
  const isDark = theme === 'dark' || theme === 'dim';
  const [searchQuery, setSearchQuery] = useState('');
  const [sortBy, setSortBy] = useState<'Trending' | 'Latest'>('Trending');
  const [mode, setMode] = useState<'Projects' | 'Architects'>('Projects');

  const filteredProjects = useMemo(() => {
    let result = projects.filter(p => 
      p.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
      p.description.toLowerCase().includes(searchQuery.toLowerCase())
    );

    if (sortBy === 'Trending') {
      result.sort((a, b) => {
        const scoreA = (a.reactions.love * 3) + (a.reactions.like * 1);
        const scoreB = (b.reactions.love * 3) + (b.reactions.like * 1);
        return scoreB - scoreA;
      });
    } else {
      result.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
    }

    return result;
  }, [projects, searchQuery, sortBy]);

  const filteredUsers = useMemo(() => {
    return users.filter(u => 
      u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      u.bio.toLowerCase().includes(searchQuery.toLowerCase()) ||
      u.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()))
    ).sort((a, b) => {
        // Prime users sorted to top of discovery
        if (a.isPrime && !b.isPrime) return -1;
        if (!a.isPrime && b.isPrime) return 1;
        return b.followers.length - a.followers.length;
    });
  }, [users, searchQuery]);

  return (
    <div className="space-y-12 animate-fade-in perspective-2000 pb-24">
      {/* Cinematic Header */}
      <section className="relative text-center py-16 overflow-hidden rounded-[4rem] bg-indigo-950/5 border border-indigo-500/10">
        <div className="absolute inset-0 bg-indigo-500/5 blur-[100px] rounded-full animate-glow-pulse"></div>
        <div className="absolute inset-0 hologram-grid opacity-20 pointer-events-none"></div>

        <div className="relative z-10 space-y-8">
          <div className="inline-block px-8 py-3 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-[11px] font-black uppercase tracking-[0.6em] text-indigo-500 animate-slide-up stagger-1 shadow-xl">
            GLOBAL ECOSYSTEM NEXUS
          </div>
          <h1 className="text-6xl md:text-8xl font-black tracking-tighter leading-none animate-slide-up stagger-2">
            THE <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-500 via-purple-500 to-indigo-600">GRID</span>
          </h1>

          <div className="max-w-3xl mx-auto relative group animate-slide-up stagger-3 px-6">
            <div className="absolute -inset-1 bg-gradient-to-r from-indigo-500/30 to-purple-500/30 rounded-[2.5rem] blur opacity-30 group-focus-within:opacity-100 transition duration-500"></div>
            <div className={`relative flex items-center p-2 rounded-[2.5rem] border-2 transition-all duration-700 ${isDark ? 'bg-black/70 border-white/10 group-focus-within:border-indigo-500/60' : 'bg-white border-slate-200 group-focus-within:border-indigo-500'}`}>
              <div className="pl-8 text-2xl opacity-40">🔍</div>
              <input 
                type="text" 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder={mode === 'Projects' ? "Synchronize with patterns..." : "Search Architects & Creators..."}
                className="flex-1 bg-transparent border-none px-6 py-5 text-2xl font-black outline-none placeholder:opacity-20 tracking-tight"
              />
            </div>
          </div>
        </div>
      </section>

      {/* View Switcher */}
      <section className="flex justify-center gap-4 animate-slide-up stagger-4">
        <div className={`flex p-1 rounded-2xl border ${isDark ? 'bg-black/40 border-white/10' : 'bg-slate-100 border-slate-200'}`}>
          {(['Projects', 'Architects'] as const).map(m => (
            <button
              key={m}
              onClick={() => setMode(m)}
              className={`px-10 py-4 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${mode === m ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'opacity-40 hover:opacity-100'}`}
            >
              {m}
            </button>
          ))}
        </div>
      </section>

      {/* Main Content Area */}
      <section className="space-y-10">
        {mode === 'Projects' ? (
          <>
            <div className="flex flex-col sm:flex-row items-center justify-between px-8 gap-8 animate-slide-up stagger-2">
              <div className="space-y-1 text-center sm:text-left">
                <h2 className="text-4xl font-black tracking-tighter uppercase">Global Repository</h2>
              </div>
              <div className="flex bg-gray-500/5 p-1.5 rounded-2xl border border-gray-500/10 backdrop-blur-sm shadow-inner">
                 {(['Trending', 'Latest'] as const).map((filter) => (
                   <button 
                    key={filter} 
                    onClick={() => setSortBy(filter)}
                    className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${sortBy === filter ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30 scale-105' : 'opacity-40 hover:opacity-100'}`}
                   >
                     {filter}
                   </button>
                 ))}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10 px-6">
              {filteredProjects.map((p, i) => (
                <ProjectCard key={p.id} project={p} index={i} isDark={isDark} onReact={onReact} creators={users} onViewProfile={onViewProfile} />
              ))}
            </div>
          </>
        ) : (
          <>
            <div className="flex flex-col sm:flex-row items-center justify-between px-8 gap-8 animate-slide-up stagger-2">
              <div className="space-y-1 text-center sm:text-left">
                <h2 className="text-4xl font-black tracking-tighter uppercase">Vortex Collective</h2>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8 px-6">
              {filteredUsers.map((u, i) => (
                <UserCard 
                  key={u.id} 
                  user={u} 
                  index={i} 
                  isDark={isDark} 
                  onFollow={onFollow} 
                  isFollowing={currentUser?.following.includes(u.id) || false}
                  isSelf={currentUser?.id === u.id}
                  onViewProfile={onViewProfile}
                />
              ))}
            </div>
          </>
        )}
      </section>
    </div>
  );
};

const ProjectCard = ({ project, index, isDark, onReact, creators, onViewProfile }: any) => {
  const creator = creators.find((u: User) => u.id === project.ownerId);
  return (
    <div className={`group relative rounded-[2.5rem] p-9 border shadow-xl hover:shadow-indigo-500/10 transition-all duration-700 animate-slide-up flex flex-col h-[400px] ${isDark ? 'bg-vortex-darkCard border-vortex-darkBorder' : 'bg-white border-slate-100'}`} style={{ animationDelay: `${0.4 + index * 0.1}s` }}>
      {creator?.isPrime && (
        <div className="absolute top-4 right-4 z-20 bg-amber-500 text-white px-3 py-1 rounded-xl text-[10px] font-black shadow-lg shadow-amber-500/30">
          👑 PRIME BUILD
        </div>
      )}
      <div className="relative z-10 flex flex-col h-full">
        <div className="flex justify-between items-start mb-8">
          <div className={`w-14 h-14 ${creator?.isPrime ? 'bg-amber-500 shadow-amber-500/20' : 'bg-indigo-600 shadow-indigo-500/20'} text-white rounded-2xl flex items-center justify-center font-black text-2xl shadow-xl transition-transform group-hover:scale-110 group-hover:-rotate-6`}>
            {project.title.charAt(0)}
          </div>
          <div className="flex flex-col items-end gap-1">
            <span className={`text-[8px] font-black ${creator?.isPrime ? 'text-amber-500 border-amber-500/20 bg-amber-500/5' : 'text-indigo-500 border-indigo-500/20 bg-indigo-500/5'} uppercase tracking-widest border px-3 py-1.5 rounded-xl`}>v2.4.0</span>
          </div>
        </div>

        <h3 className="font-black text-2xl mb-4 group-hover:text-indigo-500 transition-colors line-clamp-1 leading-none tracking-tighter">{project.title}</h3>
        <p className="text-sm opacity-50 mb-8 line-clamp-3 leading-relaxed font-medium tracking-tight italic">"{project.description}"</p>

        <div className="flex items-center justify-between pt-8 border-t border-gray-500/10 mt-auto">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => onViewProfile?.(creator?.id)}>
            <div className="relative">
              <img src={creator?.avatar || `https://picsum.photos/seed/${project.id}/48`} className={`w-11 h-11 rounded-2xl border-4 ${creator?.isPrime ? 'border-amber-500/20' : 'border-white dark:border-vortex-dark'} shadow-lg relative z-10`} alt="" />
            </div>
            <div>
               <p className="text-[8px] font-black uppercase opacity-20 leading-none tracking-widest">Architect</p>
               <p className="text-xs font-black leading-none mt-1 group-hover:text-indigo-500 transition-colors flex items-center gap-1">
                 {creator?.isPrime && <span className="text-amber-500">👑</span>}
                 @{creator?.name.toLowerCase().replace(/\s/g, '_') || 'unknown'}
               </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const UserCard = ({ user, index, isDark, onFollow, isFollowing, isSelf, onViewProfile }: any) => {
  const rankDef = useMemo(() => {
    return RANK_METRICS.find(r => r.tier === user.rank) || RANK_METRICS[RANK_METRICS.length-1];
  }, [user.rank]);

  return (
    <div className={`group relative rounded-[2.5rem] p-8 border shadow-xl transition-all duration-700 animate-slide-up flex flex-col h-[400px] hover:scale-[1.02] ${isDark ? 'bg-vortex-darkCard border-vortex-darkBorder' : 'bg-white border-slate-100'} ${user.isPrime ? 'border-amber-500/30' : ''}`} style={{ animationDelay: `${0.4 + index * 0.1}s` }}>
      {user.isPrime && (
        <div className="absolute inset-0 bg-gradient-to-br from-amber-500/5 via-transparent to-transparent rounded-[2.5rem] pointer-events-none"></div>
      )}
      <div className="relative z-10 flex flex-col h-full items-center text-center">
        <div className="absolute top-0 right-0 flex flex-col items-end gap-1.5">
          <span className={`text-[8px] font-black px-3 py-1 rounded-full uppercase tracking-widest border shadow-sm ${user.isPrime ? 'bg-amber-500 text-white border-amber-500 shadow-amber-500/40' : user.accountType === AccountType.PROFESSIONAL ? 'bg-indigo-600 text-white border-indigo-600 shadow-indigo-500/40' : 'bg-slate-500/10 text-slate-500 border-slate-500/20'}`}>
            {user.isPrime ? 'PRIME ELITE' : user.accountType}
          </span>
          <span className={`text-[7px] font-black px-2 py-0.5 rounded-md border tracking-tighter ${rankDef.bg} ${rankDef.border} ${rankDef.color}`}>
            {rankDef.icon} {rankDef.tier}
          </span>
        </div>

        <div className="relative mb-6 mt-4 cursor-pointer" onClick={() => onViewProfile?.(user.id)}>
           <div className={`absolute -inset-2 bg-gradient-to-br ${user.isPrime ? 'from-amber-400 to-yellow-600' : 'from-indigo-500 to-purple-600'} rounded-[2.2rem] blur opacity-0 group-hover:opacity-40 transition-opacity`}></div>
           <img src={user.avatar} className={`w-24 h-24 rounded-[2rem] border-4 ${user.isPrime ? 'border-amber-500' : 'border-white dark:border-vortex-dark'} shadow-2xl relative z-10 object-cover`} alt="" />
           {user.hasSkillBadge && !user.isPrime && (
             <div className="absolute -bottom-2 -right-2 bg-indigo-600 text-white w-8 h-8 flex items-center justify-center rounded-xl shadow-xl border-4 border-white dark:border-vortex-dark z-20">
               🛡️
             </div>
           )}
        </div>

        <h3 className="font-black text-xl mb-1 tracking-tighter group-hover:text-indigo-500 transition-colors cursor-pointer flex items-center justify-center gap-1.5" onClick={() => onViewProfile?.(user.id)}>
          {user.isPrime && <span className="text-amber-500">👑</span>}
          {user.name}
        </h3>
        <p className="text-[10px] font-black uppercase tracking-[0.2em] opacity-40 mb-4">{user.followers.length} Followers</p>

        <p className="text-xs opacity-50 mb-6 line-clamp-2 leading-relaxed px-2">"{user.bio}"</p>

        <div className="mt-auto w-full">
           {!isSelf ? (
             <button 
              onClick={() => onFollow(user.id)}
              className={`w-full py-4 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all transform active:scale-95 ${isFollowing ? 'bg-indigo-600/10 text-indigo-500 border border-indigo-500/20' : `${user.isPrime ? 'bg-amber-500 shadow-amber-500/30' : 'bg-indigo-600 shadow-indigo-600/30'} text-white shadow-xl hover:-translate-y-1`}`}
             >
               {isFollowing ? 'CONNECTED' : 'FOLLOW ARCHITECT'}
             </button>
           ) : (
             <button 
                onClick={() => onViewProfile?.(user.id)}
                className={`w-full py-4 border rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${user.isPrime ? 'border-amber-500 text-amber-500 hover:bg-amber-500 hover:text-white' : 'border-indigo-500/20 text-indigo-500 hover:bg-indigo-500 hover:text-white'}`}
              >
                VIEW MY STATS
             </button>
           )}
        </div>
      </div>
    </div>
  );
};

