export interface RankDef {
  tier: RankTier;
  color: string;
  glow: string;
  bg: string;
  border: string;
  icon: string;
  minScore: number;
}

export const RANK_METRICS: RankDef[] = [
  { tier: 'Grandmaster', icon: '🌌', minScore: 1000, color: 'text-white', glow: 'shadow-[0_0_15px_rgba(168,85,247,0.8)]', bg: 'bg-gradient-to-br from-purple-600 to-indigo-600', border: 'border-white/40' },
