  { threshold: 50000, value: 2.0 },
  { threshold: 10000, value: 1.1 },
  { threshold: 5000, value: 1.0 }
];

export interface RankDef {
  tier: RankTier;
  color: string;
  glow: string;
  bg: string;
  border: string;
  icon: string;
  minScore: number;
}

export const RANK_METRICS: RankDef[] = [
  { tier: 'Grandmaster', icon: '🌌', minScore: 1000, color: 'text-purple-100', glow: 'shadow-[0_0_15px_rgba(168,85,247,0.8)]', bg: 'bg-gradient-to-br from-purple-600 via-indigo-600 to-purple-800', border: 'border-purple-300/40' },
  { tier: 'Master', icon: '🔴', minScore: 500, color: 'text-red-400', glow: 'shadow-[0_0_12px_rgba(239,68,68,0.6)]', bg: 'bg-red-500/20', border: 'border-red-500/30' },
  { tier: 'Elite', icon: '🟣', minScore: 250, color: 'text-purple-400', glow: 'shadow-[0_0_12px_rgba(192,132,252,0.6)]', bg: 'bg-purple-500/20', border: 'border-purple-500/30' },
  { tier: 'Diamond', icon: '💎', minScore: 150, color: 'text-blue-400', glow: 'shadow-[0_0_12px_rgba(96,165,250,0.6)]', bg: 'bg-blue-400/20', border: 'border-blue-400/30' },
  { tier: 'Platinum', icon: '💠', minScore: 80, color: 'text-teal-400', glow: 'shadow-[0_0_10px_rgba(45,212,191,0.5)]', bg: 'bg-teal-400/20', border: 'border-teal-400/30' },
  { tier: 'Gold', icon: '🟡', minScore: 40, color: 'text-yellow-500', glow: 'shadow-[0_0_10px_rgba(234,179,8,0.5)]', bg: 'bg-yellow-500/20', border: 'border-yellow-500/30' },
  { tier: 'Silver', icon: '⚪', minScore: 15, color: 'text-slate-400', glow: 'shadow-[0_0_8px_rgba(148,163,184,0.4)]', bg: 'bg-slate-400/20', border: 'border-slate-400/30' },
  { tier: 'Drone', icon: '🤖', minScore: 0, color: 'text-gray-500', glow: 'shadow-none', bg: 'bg-gray-500/10', border: 'border-gray-500/20' },
];

export const calculateUserRank = (user: { coins: number, reputation: number }, projectCount: number): RankTier => {
  const score = (user.coins / 1000) + user.reputation + (projectCount * 2);
  const matched = RANK_METRICS.find(r => score >= r.minScore);
  return matched ? matched.tier : 'Drone';
};

