import React, { useState, useMemo } from 'react';
import { AppState, Project, User, AccountType } from '../types';
import { RANK_METRICS } from '../constants';

interface DiscoveryProps {
  state: AppState;
  onReact: (id: string, type: 'like' | 'love' | 'laugh' | 'dislike') => void;
  onFollow: (id: string) => void;
  onViewProfile?: (userId: string) => void;
}

const Discovery: React.FC<DiscoveryProps> = ({ state, onReact, onFollow, onViewProfile }) => {
  const { projects, users, currentUser, theme } = state;
  const isDark = theme === 'dark' || theme === 'dim';
  const [searchQuery, setSearchQuery] = useState('');
  const [sortBy, setSortBy] = useState<'Trending' | 'Latest'>('Trending');
  const [mode, setMode] = useState<'Projects' | 'Architects'>('Projects');

  const filteredProjects = useMemo(() => {
    let result = projects.filter(p => 
      p.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
      p.description.toLowerCase().includes(searchQuery.toLowerCase())
    );

    if (sortBy === 'Trending') {
      result.sort((a, b) => {
        const scoreA = (a.reactions.love * 3) + (a.reactions.like * 1);
        const scoreB = (b.reactions.love * 3) + (b.reactions.like * 1);
        return scoreB - scoreA;
      });
    } else {
      result.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
    }

    return result;
  }, [projects, searchQuery, sortBy]);

  const filteredUsers = useMemo(() => {
    return users.filter(u => 
      u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      u.bio.toLowerCase().includes(searchQuery.toLowerCase()) ||
      u.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()))
    ).sort((a, b) => {
        if (a.isPrime && !b.isPrime) return -1;
