export function useVortexState() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Ensure banners exist for older save data
        parsed.users = parsed.users.map((u: User) => ({ ...u, banner: u.banner || 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&q=80&w=1600' }));
        return parsed;
      } catch(e) {
        console.error("State parse error", e);
      }
    }
    return {
      currentUser: initialUsers[0],
      users: initialUsers,
      projects: demoProjects,
      messages: [],
      theme: Theme.DARK,
      subscriptionEvents: initialSubscriptionEvents
    };
  });

  // Deterministic ranking
  const rankedUsers = useMemo(() => {
    return [...state.users]
      .map(u => {
        const pCount = state.projects.filter(p => p.ownerId === u.id).length;
        const score = (u.coins / 1000) + u.reputation + (pCount * 2);
        return { ...u, globalScore: score };
      })
      .sort((a, b) => b.globalScore - a.globalScore);
  }, [state.users, state.projects]);

  const getUserGlobalIndex = useCallback((userId: string) => {
    const idx = rankedUsers.findIndex(u => u.id === userId);
    return idx === -1 ? 99 : idx + 1;
  }, [rankedUsers]);

  const updateProfile = useCallback((userId: string, updates: Partial<User>) => {
    setState(prev => {
      const targetUser = prev.users.find(u => u.id === userId);
      if (!targetUser) return prev;

      // Rule: Apurba (u1) name change restricted to every 2 months
      if (updates.name && updates.name !== targetUser.name && userId === 'u1') {
        const lastUpdate = targetUser.nameLastUpdated ? new Date(targetUser.nameLastUpdated) : new Date(0);
        const diffInMonths = (Date.now() - lastUpdate.getTime()) / (1000 * 60 * 60 * 24 * 30);
        if (diffInMonths < 2) {
          alert(`Architecture protocol restricted: Name change for identity u1 permitted once every 2 months. ${Math.ceil(60 - diffInMonths * 30)} days remaining.`);
          return prev;
        }
        updates.nameLastUpdated = new Date().toISOString();
      }

      const updatedUsers = prev.users.map(u => u.id === userId ? { ...u, ...updates } : u);
      const updatedCurrentUser = prev.currentUser?.id === userId ? { ...prev.currentUser, ...updates } : prev.currentUser;

      return { ...prev, users: updatedUsers, currentUser: updatedCurrentUser };
    });
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  useEffect(() => {
    const root = document.documentElement;
    root.classList.remove('light', 'dark', 'dim');
    if (state.theme === Theme.DIM) root.classList.add('dark', 'dim');
    else if (state.theme === Theme.DARK) root.classList.add('dark');
    else root.classList.add('light');
  }, [state.theme]);

  const addProject = useCallback((project: Project) => {
    setState(prev => {
      const updatedProjects = [project, ...prev.projects];
      const updatedUser = prev.currentUser ? { ...prev.currentUser, coins: prev.currentUser.coins + 1500 } : null;
      return {
        ...prev,
        projects: updatedProjects,
        currentUser: updatedUser,
        users: prev.users.map(u => (updatedUser && u.id === updatedUser.id) ? updatedUser : u)
      };
    });
  }, []);

  const reactToProject = useCallback((projectId: string, type: 'like' | 'love' | 'laugh' | 'dislike') => {
    setState(prev => {
      const projects = prev.projects.map(p => p.id === projectId ? { ...p, reactions: { ...p.reactions, [type]: p.reactions[type] + 1 } } : p);
      const updatedUser = prev.currentUser ? { ...prev.currentUser, coins: Math.max(0, prev.currentUser.coins + 400) } : null;
      return { ...prev, projects, currentUser: updatedUser, users: prev.users.map(u => u.id === updatedUser?.id ? updatedUser : u) };
    });
  }, []);

  const toggleFollow = useCallback((targetUserId: string) => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const isFollowing = prev.currentUser.following.includes(targetUserId);
      const updatedFollowing = isFollowing 
        ? prev.currentUser.following.filter(id => id !== targetUserId)
        : [...prev.currentUser.following, targetUserId];
      const updatedCurrentUser = { ...prev.currentUser, following: updatedFollowing };
      const updatedUsers = prev.users.map(u => {
        if (u.id === targetUserId) {
          const updatedFollowers = isFollowing ? u.followers.filter(id => id !== prev.currentUser!.id) : [...u.followers, prev.currentUser!.id];
          return { ...u, followers: updatedFollowers };
        }
        return u.id === prev.currentUser!.id ? updatedCurrentUser : u;
      });
      return { ...prev, currentUser: updatedCurrentUser, users: updatedUsers };
    });
  }, []);

  return {
    ...state,
    setTheme: (theme: Theme) => setState(p => ({ ...p, theme })),
    addProject,
    reactToProject,
    sendMessage: (msg: Message) => setState(p => ({ ...p, messages: [...p.messages, msg] })),
    toggleFollow,
    updateProfile,
    getUserGlobalIndex,
    eliteArchons: rankedUsers.slice(0, 5)
  };
}

import React, { useState } from 'react';
import { useVortexState } from './hooks/useVortexState';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProjectList from './components/ProjectList';
import Discovery from './components/Discovery';
import AIStarter from './components/AIStarter';
import Chat from './components/Chat';
import CallingUI from './components/CallingUI';
import UserProfile from './components/UserProfile';
import Subscription from './components/Subscription';

const App: React.FC = () => {
  const vortex = useVortexState();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewingUserId, setViewingUserId] = useState<string | null>(null);
  const [isAssistantCallOpen, setIsAssistantCallOpen] = useState(false);

  const handleViewProfile = (userId: string) => {
    setViewingUserId(userId);
    setActiveTab('profile');
  };

  const handleMessage = (userId: string) => {
    setActiveTab('chat');
  };

  const handleTalkToAssistant = () => {
    setIsAssistantCallOpen(true);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard state={vortex as any} />;
      case 'discovery':
        return (
          <Discovery 
            state={vortex} 
            onReact={vortex.reactToProject} 
            onFollow={vortex.toggleFollow} 
            onViewProfile={handleViewProfile}
          />
        );
      case 'projects':
        const myProjects = vortex.projects.filter(p => p.ownerId === vortex.currentUser?.id);
        return (
          <ProjectList 
            projects={myProjects} 
            onReact={vortex.reactToProject} 
            onAddProject={vortex.addProject} 
            currentUser={vortex.currentUser}
            isDark={vortex.theme !== 'light'}
          />
        );
      case 'ai-starter':
        return <AIStarter state={vortex} onProjectCreated={vortex.addProject} />;
      case 'chat':
        return (
          <Chat 
            state={{
              ...vortex,
              toggleStarUser: (vortex as any).toggleStarUser || (() => {}),
              setUserNickname: (vortex as any).setUserNickname || (() => {})
            }} 
            onSendMessage={vortex.sendMessage} 
            onViewProfile={handleViewProfile} 
          />
        );
      case 'subscription':
        return <Subscription state={vortex} onPurchase={(vortex as any).purchasePrime} onActivateDirectly={(vortex as any).activatePrimeDirectly} />;
      case 'profile':
        const displayUser = viewingUserId 
          ? vortex.users.find(u => u.id === viewingUserId) 
          : vortex.currentUser;

        if (!displayUser) return (
          <div className="flex items-center justify-center h-full text-center p-20 opacity-20">
            <div>
              <span className="text-9xl mb-10 block">📡</span>
              <p className="text-xl font-black uppercase tracking_widest">Architect Signal Lost</p>
              <button onClick={() => setActiveTab('dashboard')} className="mt-8 px-10 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest">Return to Base</button>
            </div>
          </div>
        );

        const userProjects = vortex.projects.filter(p => p.ownerId === displayUser.id);
        const isSelf = vortex.currentUser?.id === displayUser.id;
        const isFollowing = vortex.currentUser?.following.includes(displayUser.id) || false;
        const globalIndex = vortex.getUserGlobalIndex(displayUser.id);

        return (
          <>
            <UserProfile 
              user={displayUser}
              isSelf={isSelf}
              isFollowing={isFollowing}
              onFollow={vortex.toggleFollow}
              onMessage={handleMessage}
              onTalkToAssistant={handleTalkToAssistant}
              onTogglePrivacy={(vortex as any).toggleProfilePrivacy}
              projects={userProjects}
              isDark={vortex.theme !== 'light'}
              allUsers={vortex.users}
              globalIndex={globalIndex}
              onUpdateProfile={vortex.updateProfile}
            />

            {!isSelf && (
              <div className="fixed bottom-12 left-1/2 -translate-x-1/2 z-40 animate-slide-up">
                <button 
                  onClick={() => setViewingUserId(null)}
                  className="bg-black/80 backdrop-blur-md text-white px-10 py-5 rounded-full font-black text-xs uppercase tracking-[0.3em] border border-white/20 shadow-4xl hover:bg-indigo-600 transition-all hover:scale-105 active:scale-95"
                >
                  Return to my Identity
                </button>
              </div>
            )}

            <CallingUI 
              isOpen={isAssistantCallOpen} 
              onClose={() => setIsAssistantCallOpen(false)} 
              contactName={displayUser.name + " Assistant"} 
              contactAvatar={displayUser.avatar}
            />
          </>
        );
      default:
        return <Dashboard state={vortex as any} />;
    }
  };

  const handleTabChange = (tab: string) => {
    if (tab !== 'profile') setViewingUserId(null);
    setActiveTab(tab);
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={handleTabChange} 
      theme={vortex.theme} 
      setTheme={vortex.setTheme}
      user={vortex.currentUser}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

