export function useVortexState() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        return parsed;
      } catch(e) { console.error(e); }
    }
    return {
      currentUser: initialUsers[0],
      users: initialUsers,
      projects: [],
      messages: [],
      theme: Theme.DARK,
      subscriptionEvents: [],
      feedbacks: []
    };
  });

  const rankedUsers = useMemo(() => {
    return [...state.users].sort((a, b) => {
      const getScore = (u: User) => (u.coins / 1000) + u.reputation;
      return getScore(b) - getScore(a);
    });
  }, [state.users]);

  const getUserGlobalIndex = useCallback((userId: string) => {
    const idx = rankedUsers.findIndex(u => u.id === userId);
    return idx === -1 ? 99 : idx + 1;
  }, [rankedUsers]);

  const submitFeedback = useCallback((content: string) => {
    if (!state.currentUser) return;
    const feedback: Feedback = {
      id: Math.random().toString(36).substring(2, 9),
      userId: state.currentUser.id,
      userName: state.currentUser.name,
      content,
      timestamp: new Date().toISOString(),
      status: 'pending'
    };
    setState(prev => ({ ...prev, feedbacks: [feedback, ...prev.feedbacks] }));
  }, [state.currentUser]);

  const updateProfile = useCallback((userId: string, updates: Partial<User>) => {
    setState(prev => {
      const user = prev.users.find(u => u.id === userId);
      if (!user) return prev;

      if (updates.name && updates.name !== user.name && userId === 'u1') {
        const lastUpdate = user.nameLastUpdated ? new Date(user.nameLastUpdated).getTime() : 0;
        const diffDays = (Date.now() - lastUpdate) / (1000 * 3600 * 24);
        if (diffDays < 60) {
          alert(`Protocol Error: Identity "Apurba Sikder" name change permitted once every 60 days.`);
          return prev;
        }
        updates.nameLastUpdated = new Date().toISOString();
      }

      const updatedUsers = prev.users.map(u => u.id === userId ? { ...u, ...updates } : u);
      const updatedCurrentUser = prev.currentUser?.id === userId ? { ...prev.currentUser, ...updates } : prev.currentUser;
      return { ...prev, users: updatedUsers, currentUser: updatedCurrentUser };
    });
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  return {
    ...state,
    setTheme: (theme: Theme) => setState(p => ({ ...p, theme })),
    addProject: (p: Project) => setState(prev => ({ ...prev, projects: [p, ...prev.projects] })),
    reactToProject: (projectId: string, type: string) => {},
    sendMessage: (msg: Message) => setState(p => ({ ...p, messages: [...p.messages, msg] })),
    toggleFollow: (id: string) => {},
    updateProfile,
    getUserGlobalIndex,
    submitFeedback,
    eliteArchons: rankedUsers.slice(0, 5)
  };
}

