    skills: ['React', 'TypeScript', 'Node.js', 'PostgreSQL', 'Go', 'Kubernetes'],
    techStackConfidence: { 'React': 98, 'Go': 92, 'Kubernetes': 85 },
    credits: 500000,
    reputation: 950,
    isVerified: true,
    followers: [],
    following: [],
    accountType: AccountType.ENTERPRISE,
    role: 'Principal Architect',
    isPrivate: false,
    isPrime: true,
    primeUntil: new Date(Date.now() + 86400000 * 365).toISOString()
  }
];

export function useVortexState() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch(e) { console.error(e); }
    }
    return {
      currentUser: initialUsers[0],
      users: initialUsers,
      projects: [],
      messages: [],
      theme: Theme.DARK,
      feedbacks: []
    };
  });

  const updateProfile = useCallback((userId: string, updates: Partial<User>) => {
    setState(prev => {
      const updatedUsers = prev.users.map(u => u.id === userId ? { ...u, ...updates } : u);
      const updatedCurrentUser = prev.currentUser?.id === userId ? { ...prev.currentUser, ...updates } : prev.currentUser;
      return { ...prev, users: updatedUsers, currentUser: updatedCurrentUser };
    });
  }, []);

  const addProject = useCallback((p: Project) => {
    setState(prev => ({ ...prev, projects: [p, ...prev.projects] }));
  }, []);

  const submitFeedback = useCallback((content: string) => {
    if (!state.currentUser) return;
    const feedback: Feedback = {
      id: Math.random().toString(36).substring(2, 9),
      userId: state.currentUser.id,
      userName: state.currentUser.name,
      content,
      timestamp: new Date().toISOString(),
      status: 'pending'
    };
    setState(prev => ({ ...prev, feedbacks: [feedback, ...prev.feedbacks] }));
  }, [state.currentUser]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  return {
    ...state,
    setTheme: (theme: Theme) => setState(p => ({ ...p, theme })),
    addProject,
    updateProfile,
    submitFeedback,
    getUserGlobalIndex: (id: string) => 1,
    eliteArchons: state.users.slice(0, 5)
  };
}

