import { useState, useEffect, useCallback } from 'react';
import { User, Project, Message, Theme, AppState, AccountType, Feedback, SubscriptionEvent } from '../types';

const STORAGE_KEY = 'vortex_pro_v1';

const initialUsers: User[] = [
  {
    id: 'u1',
    name: 'Apurba Sikder',
    email: 'apurba@vortex.dev',
    avatar: 'https://picsum.photos/seed/vortex/200',
    banner: 'https://images.unsplash.com/photo-1497215728101-856f4ea42174?auto=format&fit=crop&q=80&w=1600',
    bio: 'Lead Architect specializing in high-frequency trading systems and distributed ledger tech.',
    skills: ['React', 'TypeScript', 'Node.js', 'PostgreSQL', 'Go', 'Kubernetes'],
    techStackConfidence: { 'React': 98, 'Go': 92, 'Kubernetes': 85 },
    credits: 500000,
    reputation: 950,
    isVerified: true,
    followers: [],
    following: [],
    accountType: AccountType.ENTERPRISE,
    role: 'Principal Architect',
    isPrivate: false,
    isPrime: true,
    primeUntil: new Date(Date.now() + 86400000 * 365).toISOString(),
    nicknames: {},
    starredUsers: [],
    rank: 'Echelon I'
  }
];

export function useVortexState() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch(e) { console.error(e); }
    }
    return {
      currentUser: initialUsers[0],
      users: initialUsers,
      projects: [],
      messages: [],
      theme: Theme.DARK,
      feedbacks: [],
      subscriptionEvents: []
    };
  });

  const updateProfile = useCallback((userId: string, updates: Partial<User>) => {
    setState(prev => {
      const updatedUsers = prev.users.map(u => u.id === userId ? { ...u, ...updates } : u);
      const updatedCurrentUser = prev.currentUser?.id === userId ? { ...prev.currentUser, ...updates } : prev.currentUser;
      return { ...prev, users: updatedUsers, currentUser: updatedCurrentUser };
    });
  }, []);

  const addProject = useCallback((p: Project) => {
    setState(prev => ({ ...prev, projects: [p, ...prev.projects] }));
  }, []);

  const submitFeedback = useCallback((content: string) => {
    if (!state.currentUser) return;
    const feedback: Feedback = {
      id: Math.random().toString(36).substring(2, 9),
      userId: state.currentUser.id,
      userName: state.currentUser.name,
      content,
      timestamp: new Date().toISOString(),
      status: 'pending'
    };
    setState(prev => ({ ...prev, feedbacks: [feedback, ...prev.feedbacks] }));
  }, [state.currentUser]);

  // Added missing toggleFollow
  const toggleFollow = useCallback((targetId: string) => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const isFollowing = prev.currentUser.following.includes(targetId);
      const updatedFollowing = isFollowing 
        ? prev.currentUser.following.filter(id => id !== targetId)
        : [...prev.currentUser.following, targetId];

      const updatedCurrentUser = { ...prev.currentUser, following: updatedFollowing };
      const updatedUsers = prev.users.map(u => u.id === prev.currentUser?.id ? updatedCurrentUser : u);

      return { ...prev, currentUser: updatedCurrentUser, users: updatedUsers };
    });
  }, []);

  // Added missing reactToProject (mock implementation)
  const reactToProject = useCallback((projectId: string, type: string) => {
    console.debug(`Reacted to project ${projectId} with ${type}`);
  }, []);

  // Added missing sendMessage
  const sendMessage = useCallback((msg: Message) => {
    setState(prev => ({ ...prev, messages: [...prev.messages, msg] }));
  }, []);

  // Added missing toggleStarUser
  const toggleStarUser = useCallback((userId: string) => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const starred = prev.currentUser.starredUsers || [];
      const isStarred = starred.includes(userId);
      const updatedStarred = isStarred 
        ? starred.filter(id => id !== userId)
        : [...starred, userId];

      const updatedCurrentUser = { ...prev.currentUser, starredUsers: updatedStarred };
      const updatedUsers = prev.users.map(u => u.id === prev.currentUser?.id ? updatedCurrentUser : u);

      return { ...prev, currentUser: updatedCurrentUser, users: updatedUsers };
    });
  }, []);

  // Added missing setUserNickname
  const setUserNickname = useCallback((userId: string, nickname: string) => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const nicknames = { ...(prev.currentUser.nicknames || {}), [userId]: nickname };
      const updatedCurrentUser = { ...prev.currentUser, nicknames };
      const updatedUsers = prev.users.map(u => u.id === prev.currentUser?.id ? updatedCurrentUser : u);
      return { ...prev, currentUser: updatedCurrentUser, users: updatedUsers };
    });
  }, []);

  // Added missing subscription methods
  const purchasePrime = useCallback((cost: number) => {
    setState(prev => {
      if (!prev.currentUser || prev.currentUser.credits < cost) return prev;
      const updatedCurrentUser = { 
        ...prev.currentUser, 
        credits: prev.currentUser.credits - cost,
        isPrime: true,
        primeUntil: new Date(Date.now() + 86400000 * 7).toISOString()
      };
      return { ...prev, currentUser: updatedCurrentUser };
    });
  }, []);

  const activatePrimeDirectly = useCallback((days: number, tierLabel: string) => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const updatedCurrentUser = { 
        ...prev.currentUser, 
        isPrime: true,
        primeUntil: new Date(Date.now() + 86400000 * days).toISOString()
      };
      const event: SubscriptionEvent = {
        id: Math.random().toString(36).substr(2, 9),
        userId: prev.currentUser.id,
        userName: prev.currentUser.name,
        userAvatar: prev.currentUser.avatar,
        tierName: tierLabel,
        timestamp: new Date().toISOString()
      };
      return { ...prev, currentUser: updatedCurrentUser, subscriptionEvents: [event, ...prev.subscriptionEvents] };
    });
  }, []);

  const toggleProfilePrivacy = useCallback(() => {
    setState(prev => {
      if (!prev.currentUser) return prev;
      const updatedCurrentUser = { ...prev.currentUser, isPrivate: !prev.currentUser.isPrivate };
      return { ...prev, currentUser: updatedCurrentUser };
    });
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  return {
    ...state,
    setTheme: (theme: Theme) => setState(p => ({ ...p, theme })),
    addProject,
    updateProfile,
    submitFeedback,
    toggleFollow,
    reactToProject,
    sendMessage,
    toggleStarUser,
    setUserNickname,
    purchasePrime,
    activatePrimeDirectly,
    toggleProfilePrivacy,
    getUserGlobalIndex: (id: string) => state.users.findIndex(u => u.id === id) + 1,
    eliteArchons: state.users.slice(0, 5)
  };
}

import React, { useState } from 'react';
import { geminiService } from '../services/gemini';
import { AppState, Project } from '../types';

interface AIStarterProps {
  state: AppState;
  onProjectCreated: (p: Project) => void;
}

const AIStarter: React.FC<AIStarterProps> = ({ state, onProjectCreated }) => {
  const [interest, setInterest] = useState('');
  const [loading, setLoading] = useState(false);
  const [suggestion, setSuggestion] = useState<any>(null);
  const [isDragging, setIsDragging] = useState(false);
  const { theme } = state;
  const isDark = theme === 'dark' || theme === 'dim';

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = () => {
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const files = Array.from(e.dataTransfer.files);
    if (files.length > 0) {
      setInterest(`Based on dropped file context: ${files[0].name}. Building an architecture around this conceptual payload.`);
    }
  };

  const handleGenerate = async () => {
    if (!interest || !state.currentUser) return;
    setLoading(true);
    try {
      // Fix: generateProjectGenesis instead of generateProjectStarter
      const result = await geminiService.generateProjectGenesis(state.currentUser.skills, interest);
      setSuggestion(result);
    } catch (e) {
      console.error(e);
      alert('Neural sync failed. Check API key integrity.');
    } finally {
      setLoading(false);
    }
  };

  const handleLaunch = () => {
    if (!suggestion || !state.currentUser) return;
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      ownerId: state.currentUser.id,
      title: suggestion.title,
      description: suggestion.description,
      techStack: suggestion.techStack || [],
      dependencies: [],
      files: (suggestion.starterFiles || []).map((f: any) => ({
        name: f.name,
        content: f.content,
        language: f.language
      })),
      externalLinks: [],
      roadmap: (suggestion.roadmap || []).map((r: any, idx: number) => ({
        id: `m-${idx}`,
        label: r.label,
        status: r.status === 'completed' ? 'completed' : 'pending'
      })),
      reviews: [],
      metrics: {
        testCoverage: 0,
        techDebt: 0,
        deploymentFrequency: 0
      },
      isPublic: true,
      createdAt: new Date().toISOString()
    };
    onProjectCreated(newProject);
    setSuggestion(null);
    setInterest('');
  };

  return (
    <div 
      className="max-w-7xl mx-auto space-y-12 animate-fade-in py-6 pb-48 perspective-2000"
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
