               <p className="text-sm font-black text-yellow-600 leading-none">{user?.coins.toLocaleString()}</p>
             </div>

             <div className={`flex items-center gap-1.5 p-1 rounded-full border ${isDark || isDim ? 'bg-black/40 border-white/10' : 'bg-slate-100 border-slate-200'}`}>
                {themeOptions.map((opt) => (
                  <button
                    key={opt.key}
                    onClick={() => setTheme(opt.key)}
                    className={`w-7 h-7 flex items-center justify-center rounded-full transition-all group relative ${
                      theme === opt.key ? 'bg-indigo-600 text-white shadow-lg' : 'opacity-40 hover:opacity-100'
                    }`}
                  >
                    <span className="text-[11px] font-black uppercase tracking-tighter">{opt.label}</span>
                  </button>
                ))}
             </div>

            <div className="relative group cursor-pointer" onClick={() => setActiveTab('profile')}>
              <img src={user?.avatar} alt="Profile" className={`w-11 h-11 rounded-xl border-2 border-indigo-500/30 transition-transform duration-500 group-hover:scale-105`} />
