          </div>
        </header>

        <div className={`flex-1 overflow-y-auto custom-scrollbar transition-all duration-700 ${getContainerStyles()}`}>
          <div className="p-8 max-w-[1600px] mx-auto animate-slide-up">
            {children}
          </div>
        </div>
      </main>

      {/* Guide Modal (PUJWAN_MANUAL) - Optimized for Clarity and Scale */}
      {showGuideModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 md:p-10 bg-black/95 backdrop-blur-3xl animate-in fade-in duration-500">
          <div className={`w-full max-w-5xl rounded-[3rem] border-2 p-8 md:p-10 space-y-6 animate-in zoom-in-95 duration-500 relative overflow-hidden shadow-4xl h-[90vh] flex flex-col ${isDark || isDim ? 'bg-vortex-darkCard border-indigo-500/30' : 'bg-white border-slate-200'}`}>
            <div className="absolute top-0 right-0 w-80 h-80 bg-indigo-600/10 blur-[100px] rounded-full pointer-events-none"></div>

            <div className="flex items-center justify-between border-b border-gray-500/10 pb-6">
              <div className="flex items-center gap-5">
                <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-lg shadow-xl text-white">📘</div>
                <div className="space-y-0.5">
                  <h3 className="text-xl font-black tracking-tighter uppercase leading-none">VORTEX_GUIDEBOOK</h3>
                  <p className="text-[10px] font-black uppercase tracking-[0.4em] text-indigo-500 opacity-60">Protocol Manual • Persona: arch_pujwan</p>
                </div>
              </div>
              <button onClick={() => setShowGuideModal(false)} className="w-10 h-10 rounded-full flex items-center justify-center bg-gray-500/10 hover:bg-red-500/20 hover:text-red-500 transition-all text-xl">×</button>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar pr-6 space-y-12 py-4">
              <section className="space-y-4">
                <h4 className="text-[10px] font-black uppercase tracking-[0.5em] text-indigo-500 border-l-4 border-indigo-600 pl-4">01. THE_ECOSYSTEM_PURPOSE</h4>
                <div className="space-y-6">
                  <p className="text-lg opacity-80 leading-relaxed font-medium">
                    VORTEX is a high-performance neural environment where developers manifest, showcase, and monetize technical artifacts. It serves as a bridge between individual talent and global technical prestige.
                  </p>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                     {[
                       { t: "BUILD", d: "Instantiate full-scale codebases from raw conceptual payloads." },
                       { t: "VERIFY", d: "Establish technical trust through reputation-based evaluations." },
                       { t: "ASCEND", d: "Climb the Global Grid to secure elite visibility and capital." }
                     ].map(item => (
                       <div key={item.t} className="p-4 rounded-2xl bg-indigo-500/5 border border-indigo-500/10">
                         <p className="text-indigo-400 font-black text-[9px] uppercase mb-1">{item.t}</p>
                         <p className="text-[11px] opacity-40 font-medium leading-tight">{item.d}</p>
                       </div>
                     ))}
                  </div>
                </div>
              </section>

              <section className="space-y-6">
                <h4 className="text-[10px] font-black uppercase tracking-[0.5em] text-indigo-500 border-l-4 border-indigo-600 pl-4">02. PRIMARY_CAPABILITIES</h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="p-8 rounded-[2.5rem] bg-indigo-500/5 border border-indigo-500/20 space-y-4 hover:border-indigo-500/40 transition-all group">
                    <div className="flex items-center gap-3">
                      <span className="text-2xl">🛠️</span>
                      <h5 className="text-[12px] font-black uppercase tracking-widest text-indigo-400">GENESIS_AI_STARTER</h5>
                    </div>
                    <p className="text-sm opacity-60 leading-relaxed">
                      Transmit your vision via AI Starter. The engine synthesizes roadmaps and scaffolds, allowing you to manifest repositories from pure intent.
                    </p>
                  </div>
                  <div className="p-8 rounded-[2.5rem] bg-purple-500/5 border border-purple-500/20 space-y-4 hover:border-purple-500/40 transition-all group">
                    <div className="flex items-center gap-3">
                      <span className="text-2xl">📡</span>
                      <h5 className="text-[12px] font-black uppercase tracking-widest text-purple-400">NEURAL_SYNC_NODES</h5>
                    </div>
                    <p className="text-sm opacity-60 leading-relaxed">
                      Collaborate via synchronous chat or <strong>Live Audio Handshakes</strong>. Use the Calling UI to troubleshoot with AI personas in real-time.
                    </p>
                  </div>
                </div>
              </section>

              <section className="space-y-6">
                <h4 className="text-[10px] font-black uppercase tracking-[0.5em] text-indigo-500 border-l-4 border-indigo-600 pl-4">03. PROTOCOL_RANKINGS</h4>
                <div className="flex flex-wrap gap-4">
                  {RANK_METRICS.slice(0, 4).reverse().map(r => (
                    <div key={r.tier} className={`px-5 py-3 rounded-2xl border flex items-center gap-3 transition-transform hover:scale-105 ${r.bg} ${r.border}`}>
                      <span className="text-xl">{r.icon}</span>
                      <div className="text-left">
                        <p className={`text-[10px] font-black uppercase tracking-widest ${r.color}`}>{r.tier}</p>
                        <p className="text-[7px] font-bold opacity-30 uppercase">Neural Status Verified</p>
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            </div>

            <div className="flex justify-center pt-4 border-t border-gray-500/10">
              <button onClick={() => setShowGuideModal(false)} className="px-14 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[11px] uppercase tracking-[0.3em] shadow-2xl hover:bg-indigo-700 transition-all">ACKNOWLEDGE_PROTOCOL</button>
            </div>
          </div>
        </div>
      )}

      {showFeedbackModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in duration-300">
          <div className={`w-full max-w-xl rounded-[3rem] border-2 p-12 space-y-10 animate-in zoom-in-95 duration-500 relative overflow-hidden ${isDark || isDim ? 'bg-vortex-darkCard border-indigo-500/20' : 'bg-white border-slate-200 shadow-4xl'}`}>
            <h3 className="text-3xl font-black tracking-tighter uppercase">ANOMALY_REPORT</h3>
            <textarea 
              value={feedbackContent}
              onChange={(e) => setFeedbackContent(e.target.value)}
              placeholder="Describe the problem to be fixed..."
              className={`w-full px-8 py-6 rounded-3xl text-lg font-medium outline-none border-2 transition-all h-48 ${isDark || isDim ? 'bg-black/40 border-white/5 focus:border-indigo-500' : 'bg-slate-50 border-slate-200 focus:border-indigo-500'}`}
            />
            <div className="flex gap-4">
              <button onClick={() => setShowFeedbackModal(false)} className="flex-1 py-6 rounded-3xl font-black text-xs uppercase tracking-widest border border-gray-500/10">ABORT</button>
              <button onClick={handleFeedbackSubmit} className="flex-[2] py-6 bg-indigo-600 text-white rounded-3xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-600/30">FIX_ANOMALY</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Layout;

import React from 'react';
import { AppState, Project } from '../types';

