    <div className="space-y-12 animate-fade-in pb-32">
      <section className={`relative rounded-[2.5rem] p-12 overflow-hidden border ${isDark ? 'bg-vortex-darkCard border-vortex-darkBorder' : 'bg-white border-slate-200 shadow-xl'}`}>
