        <div className="relative z-10 space-y-6">
          <h1 className="text-5xl font-black tracking-tighter leading-none">Welcome back, {currentUser?.name.split(' ')[0]}.</h1>
          <p className="text-lg opacity-50 max-w-2xl font-medium">The ecosystem is synchronized. 12 new architectural payloads detected in your sector since last manifestation.</p>
          <div className="flex gap-4 pt-4">
            <button className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-bold text-sm hover:scale-105 transition-all shadow-xl shadow-indigo-600/30">New Build</button>
