export default Dashboard;

import React, { useMemo, useState } from 'react';
import { User, Project } from '../types';
import { RANK_METRICS } from '../constants';

interface UserProfileProps {
  user: User;
  isSelf: boolean;
  isFollowing: boolean;
  onFollow: (id: string) => void;
  onMessage: (id: string) => void;
  onTalkToAssistant: () => void;
  onTogglePrivacy?: () => void;
  projects: Project[];
  isDark: boolean;
  allUsers: User[];
  globalIndex: number;
  onUpdateProfile?: (userId: string, updates: Partial<User>) => void;
}

const UserProfile: React.FC<UserProfileProps> = ({ 
  user, isSelf, isFollowing, onFollow, onMessage, 
  onTalkToAssistant, projects, isDark, globalIndex, onUpdateProfile 
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState(user.name);
  const [editBio, setEditBio] = useState(user.bio);
  const [editBanner, setEditBanner] = useState(user.banner);
  const [editSkills, setEditSkills] = useState(user.skills.join(', '));
  const [editPrivacy, setEditPrivacy] = useState(user.isPrivate);

  const rankDef = useMemo(() => {
    return RANK_METRICS.find(r => r.tier === user.rank) || RANK_METRICS[RANK_METRICS.length - 1];
  }, [user.rank]);

  const handleSave = () => {
    onUpdateProfile?.(user.id, {
      name: editName,
      bio: editBio,
      banner: editBanner,
      skills: editSkills.split(',').map(s => s.trim()).filter(s => s),
      isPrivate: editPrivacy
    });
    setIsEditing(false);
  };

  const isProfileLocked = user.isPrivate && !isSelf;

  return (
    <div className="max-w-6xl mx-auto animate-slide-up pb-32">
      <div className="relative mb-28 group/banner">
        <div className={`h-80 md:h-[450px] rounded-[4rem] shadow-3xl overflow-hidden relative transition-all duration-1000 ${isDark ? 'bg-indigo-950/20' : 'bg-slate-100'}`}>
          <img src={isProfileLocked ? 'https://images.unsplash.com/photo-1557683316-973673baf926?auto=format&fit=crop&q=80&w=1600' : user.banner} className={`w-full h-full object-cover ${isProfileLocked ? 'blur-md opacity-40' : ''}`} alt="Banner" />
          <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent"></div>
          {isSelf && (
            <button 
              onClick={() => setIsEditing(true)}
              className="absolute top-8 right-8 bg-white/10 backdrop-blur-md border border-white/20 text-white px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest opacity-0 group-hover/banner:opacity-100 transition-all hover:bg-white/20"
            >
              CHANGE_BANNER
            </button>
          )}
        </div>

        <div className="absolute -bottom-24 left-10 right-10 flex flex-col md:flex-row items-center md:items-end gap-10">
          <div className="relative group shrink-0">
            <div className={`absolute -inset-2 bg-gradient-to-br ${user.isPrime ? 'from-amber-400 to-amber-600' : 'from-indigo-500 to-purple-600'} rounded-[4rem] blur opacity-40 group-hover:opacity-80 transition duration-1000`}></div>
            <img src={isProfileLocked ? 'https://www.gravatar.com/avatar/00000000000000000000000000000000?d=mp&f=y' : user.avatar} className="relative w-48 h-48 md:w-56 md:h-56 rounded-[3.8rem] border-8 border-black shadow-4xl object-cover z-10" alt={user.name} />
            <div className={`absolute bottom-4 right-4 w-12 h-12 rounded-full border-4 border-black z-20 flex items-center justify-center ${rankDef.bg} ${rankDef.glow}`}>
               <span className="text-xl">{rankDef.icon}</span>
            </div>
          </div>

          <div className="flex-1 text-center md:text-left pb-6 space-y-4">
            <h1 className="text-5xl md:text-7xl font-black tracking-tighter text-white drop-shadow-2xl leading-none">{user.name}</h1>
            <div className="flex flex-wrap items-center justify-center md:justify-start gap-3">
              <span className="text-lg font-bold text-white/60 tracking-widest font-mono">@{user.name.toLowerCase().replace(/\s/g, '_')}</span>
              {user.isPrime && <span className="px-4 py-1.5 bg-amber-500 text-black rounded-full text-[9px] font-black uppercase tracking-widest shadow-lg shadow-amber-500/20">VORTEX_PRIME</span>}
              <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest border shadow-lg ${rankDef.bg} ${rankDef.border} ${rankDef.color}`}>RANK: {rankDef.tier}</span>
            </div>
          </div>

          <div className="pb-8 flex gap-4">
             {isSelf ? (
                <button onClick={() => setIsEditing(true)} className="px-10 py-5 bg-indigo-600 text-white rounded-3xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-600/40 hover:scale-105 active:scale-95 transition-all">EDIT_IDENTITY</button>
             ) : !isProfileLocked && (
                <button onClick={() => onFollow(user.id)} className={`px-10 py-5 rounded-3xl font-black text-xs uppercase tracking-widest transition-all shadow-2xl ${isFollowing ? 'bg-slate-500/10 text-slate-500 border border-slate-500/20' : 'bg-indigo-600 text-white shadow-indigo-600/30'}`}>
                  {isFollowing ? 'CONNECTED' : 'FOLLOW'}
                </button>
             )}
          </div>
        </div>
      </div>

      <section className={`mt-32 p-12 rounded-[4rem] border shadow-4xl flex flex-wrap items-center justify-between gap-12 relative overflow-hidden ${isDark ? 'bg-vortex-darkCard border-vortex-darkBorder' : 'bg-white border-slate-100'}`}>
        <div className="flex items-center gap-16">
          <Stat label="Global Rank" value={`#${globalIndex}`} sub="Deterministic Score" isPrime={user.isPrime} />
          <div className="w-px h-20 bg-gray-500/10"></div>
          <Stat label="Reputation" value={`${user.reputation}%`} sub="Verified" />
        </div>
        {!isProfileLocked && (
          <div className="flex items-center gap-16">
            <Stat label="Assets" value={`🪙 ${user.coins.toLocaleString()}`} sub="Current Liquid" />
            <div className="w-px h-20 bg-gray-500/10"></div>
            <Stat label="Deployments" value={projects.length} sub="Active Builds" />
          </div>
        )}
      </section>

      <section className="mt-16">
        <div className={`p-16 rounded-[4rem] border shadow-2xl ${isDark ? 'bg-black/20 border-white/5' : 'bg-white border-slate-50'}`}>
          <h3 className="text-[10px] font-black uppercase tracking-[0.5em] text-indigo-500/60 mb-10">ARCHITECT_NARRATIVE</h3>
          <p className="text-4xl md:text-5xl font-medium leading-[1.1] tracking-tighter italic opacity-90">"{user.bio}"</p>
          <div className="mt-16 pt-12 border-t border-gray-500/5">
            <div className="flex flex-wrap gap-4">
              {user.skills.map(s => (
                <span key={s} className={`px-8 py-4 rounded-2xl text-[11px] font-black uppercase tracking-widest border ${isDark ? 'bg-white/5 border-white/10 text-white/50' : 'bg-slate-100 border-slate-200 text-slate-600 shadow-sm'}`}>
                  {s}
                </span>
              ))}
            </div>
          </div>
        </div>
      </section>

      {isEditing && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in duration-300">
          <div className={`w-full max-w-2xl rounded-[4rem] border-2 p-16 space-y-10 shadow-4xl animate-in zoom-in-95 duration-500 max-h-[90vh] overflow-y-auto custom-scrollbar ${isDark ? 'bg-vortex-darkCard border-indigo-500/20' : 'bg-white border-slate-200'}`}>
            <h2 className="text-4xl font-black tracking-tighter uppercase">RECONFIGURE_ID</h2>
            <div className="space-y-8">
               <Input label="NAME" value={editName} onChange={setEditName} />
               <Input label="BANNER_URL" value={editBanner} onChange={setEditBanner} />
               <div className="space-y-3">
                 <label className="text-[10px] font-black uppercase tracking-[0.4em] opacity-30">BIO</label>
                 <textarea value={editBio} onChange={(e) => setEditBio(e.target.value)} className={`w-full px-8 py-6 rounded-3xl text-lg font-medium outline-none border-2 transition-all h-40 ${isDark ? 'bg-black/40 border-white/5 focus:border-indigo-500' : 'bg-slate-50 border-slate-200 focus:border-indigo-500'}`} />
               </div>
               <Input label="SKILLS (COMMA SEPARATED)" value={editSkills} onChange={setEditSkills} />
            </div>
            <div className="flex gap-4 pt-4">
              <button onClick={() => setIsEditing(false)} className="flex-1 py-6 rounded-3xl font-black text-xs uppercase tracking-widest border border-gray-500/10">ABORT</button>
              <button onClick={handleSave} className="flex-[2] py-6 bg-indigo-600 text-white rounded-3xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-600/30 hover:scale-[1.02] active:scale-95 transition-all">SYNC</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const Stat = ({ label, value, sub, isPrime }: any) => (
  <div className="space-y-1">
    <p className="text-[11px] font-black uppercase opacity-20 tracking-[0.5em]">{label}</p>
    <p className={`text-5xl font-black tracking-tighter leading-none ${isPrime ? 'text-amber-500' : ''}`}>{value}</p>
    <p className="text-[9px] font-bold opacity-30 uppercase tracking-widest mt-2">{sub}</p>
  </div>
);

const Input = ({ label, value, onChange }: any) => (
  <div className="space-y-3">
    <label className="text-[10px] font-black uppercase tracking-[0.4em] opacity-30">{label}</label>
    <input type="text" value={value} onChange={(e) => onChange(e.target.value)} className="w-full px-8 py-6 rounded-3xl text-xl font-black outline-none border-2 transition-all bg-black/40 border-white/5 focus:border-indigo-500 dark:text-white" />
  </div>
);

export default UserProfile;

