      )}

      <div className="text-center space-y-4">
        <h2 className="text-6xl md:text-7xl font-black tracking-tighter uppercase">Nexus Subscription</h2>
        <p className="text-xl opacity-40 max-w-2xl mx-auto font-medium italic">
