      <div className={`relative w-full max-w-lg p-10 md:p-16 rounded-[4rem] border-2 shadow-4xl backdrop-blur-3xl animate-slide-up ${isDark ? 'bg-vortex-darkCard/80 border-white/5' : 'bg-white/80 border-slate-200'}`}>
        <div className="text-center space-y-4 mb-12">
          <div className="inline-flex w-16 h-16 bg-indigo-600 rounded-3xl items-center justify-center shadow-2xl shadow-indigo-600/40 transform -rotate-6 mb-4">
            <span className="text-white font-black text-3xl">V</span>
          </div>
          <h1 className="text-4xl font-black tracking-tighter uppercase leading-none">Vortex Genesis</h1>
          <p className="text-xs font-black uppercase tracking-[0.4em] opacity-30">Neural Authentication Protocol</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {!isLogin && (
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase tracking-[0.4em] opacity-30 px-2">Architect Identity</label>
              <input 
                type="text" 
                value={name}
                onChange={(e) => setName(e.target.value)}
