              />
            </div>
          )}

          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase tracking-[0.4em] opacity-30 px-2">Email Hash</label>
            <input 
              type="email" 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="architect@vortex.mesh"
              className={`w-full px-6 py-4 rounded-2xl text-sm font-bold outline-none border-2 transition-all ${isDark ? 'bg-black/40 border-white/5 focus:border-indigo-500 text-white' : 'bg-slate-50 border-slate-200 focus:border-indigo-500'}`}
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase tracking-[0.4em] opacity-30 px-2">Access Key</label>
            <input 
              type="password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
