              className={`w-full px-6 py-4 rounded-2xl text-sm font-bold outline-none border-2 transition-all ${isDark ? 'bg-black/40 border-white/5 focus:border-indigo-500 text-white' : 'bg-slate-50 border-slate-200 focus:border-indigo-500'}`}
