            <p className="text-[10px] font-black uppercase text-red-500 text-center animate-pulse">{error}</p>
          )}

          <button 
            type="submit"
            className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-600/30 transition-all hover:scale-[1.02] active:scale-95 mt-4"
          >
            {isLogin ? 'Initialize Uplink' : 'Manifest Identity'}
