import Dashboard from './components/Dashboard';
import ProjectList from './components/ProjectList';
import Discovery from './components/Discovery';
import AIStarter from './components/AIStarter';
import Chat from './components/Chat';
import CallingUI from './components/CallingUI';
import UserProfile from './components/UserProfile';
import Subscription from './components/Subscription';
import Auth from './components/Auth';

const App: React.FC = () => {
  const vortex = useVortexState();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewingUserId, setViewingUserId] = useState<string | null>(null);
  const [isAssistantCallOpen, setIsAssistantCallOpen] = useState(false);

  const handleViewProfile = (userId: string) => {
    setViewingUserId(userId);
    setActiveTab('profile');
  };

  const handleMessage = (userId: string) => {
    setActiveTab('chat');
  };

  const handleTalkToAssistant = () => {
    setIsAssistantCallOpen(true);
  };

  if (!vortex.currentUser) {
    return (
      <Auth 
        isDark={vortex.theme !== 'light'} 
        onLogin={vortex.login} 
        onSignup={vortex.signup} 
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard state={vortex as any} onReact={vortex.reactToProject} onViewProfile={handleViewProfile} />;
      case 'discovery':
        return (
          <Discovery 
            state={vortex} 
            onReact={vortex.reactToProject} 
            onFollow={vortex.toggleFollow} 
            onViewProfile={handleViewProfile}
          />
        );
      case 'projects':
        const myProjects = vortex.projects.filter(p => p.ownerId === vortex.currentUser?.id);
        return (
          <ProjectList 
            projects={myProjects} 
            onReact={vortex.reactToProject} 
            onAddProject={vortex.addProject} 
            currentUser={vortex.currentUser}
            isDark={vortex.theme !== 'light'}
          />
        );
      case 'ai-starter':
        return <AIStarter state={vortex} onProjectCreated={vortex.addProject} />;
      case 'chat':
        return (
          <Chat 
            state={{
              ...vortex,
              toggleStarUser: (vortex as any).toggleStarUser || (() => {}),
              setUserNickname: (vortex as any).setUserNickname || (() => {})
            }} 
            onSendMessage={vortex.sendMessage} 
            onViewProfile={handleViewProfile} 
          />
        );
      case 'subscription':
        return <Subscription state={vortex} onPurchase={(vortex as any).purchasePrime} onActivateDirectly={(vortex as any).activatePrimeDirectly} />;
      case 'profile':
        const displayUser = viewingUserId 
          ? vortex.users.find(u => u.id === viewingUserId) 
          : vortex.currentUser;

        if (!displayUser) return (
          <div className="flex items-center justify-center h-full text-center p-20 opacity-20">
            <div>
              <span className="text-9xl mb-10 block">📡</span>
              <p className="text-xl font-black uppercase tracking-widest">Architect Signal Lost</p>
              <button onClick={() => setActiveTab('dashboard')} className="mt-8 px-10 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest">Return to Base</button>
            </div>
          </div>
        );

        const userProjects = vortex.projects.filter(p => p.ownerId === displayUser.id);
        const isSelf = vortex.currentUser?.id === displayUser.id;
        const isFollowing = vortex.currentUser?.following.includes(displayUser.id) || false;
        const globalIndex = vortex.getUserGlobalIndex(displayUser.id);

        return (
          <>
            <UserProfile 
              user={displayUser}
              isSelf={isSelf}
              isFollowing={isFollowing}
              onFollow={vortex.toggleFollow}
              onMessage={handleMessage}
              onTalkToAssistant={handleTalkToAssistant}
              onTogglePrivacy={(vortex as any).toggleProfilePrivacy}
              projects={userProjects}
              isDark={vortex.theme !== 'light'}
              allUsers={vortex.users}
              globalIndex={globalIndex}
              onUpdateProfile={vortex.updateProfile}
            />

            {!isSelf && (
              <div className="fixed bottom-12 left-1/2 -translate-x-1/2 z-40 animate-slide-up">
                <button 
                  onClick={() => setViewingUserId(null)}
                  className="bg-black/80 backdrop-blur-md text-white px-10 py-5 rounded-full font-black text-xs uppercase tracking-[0.3em] border border-white/20 shadow-4xl hover:bg-indigo-600 transition-all hover:scale-105 active:scale-95"
                >
                  Return to my Identity
                </button>
              </div>
            )}

            <CallingUI 
              isOpen={isAssistantCallOpen} 
              onClose={() => setIsAssistantCallOpen(false)} 
              contactName={displayUser.name + " Assistant"} 
              contactAvatar={displayUser.avatar}
            />
          </>
        );
      default:
        return <Dashboard state={vortex as any} onReact={vortex.reactToProject} onViewProfile={handleViewProfile} />;
    }
  };

  const handleTabChange = (tab: string) => {
    if (tab !== 'profile') setViewingUserId(null);
    setActiveTab(tab);
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={handleTabChange} 
      theme={vortex.theme} 
      setTheme={vortex.setTheme}
      user={vortex.currentUser}
      onSubmitFeedback={vortex.submitFeedback}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { AppState, Project } from '../types';

interface DashboardProps {
  state: AppState;
  onReact: (id: string, type: string) => void;
  onViewProfile: (userId: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ state, onReact, onViewProfile }) => {
  const { currentUser, projects, theme } = state;
  const isDark = theme !== 'light';
  const [isScannerOpen, setIsScannerOpen] = useState(false);
  const [isScanning, setIsScanning] = useState(false);

  const timeContext = useMemo(() => {
    const hour = new Date().getHours();
    if (hour >= 5 && hour < 12) {
      return { 
        id: 'morning',
        greeting: "Good Morning", 
        status: "System Initialization", 
        icon: "🌅", 
        accent: "text-amber-500",
        bg: "from-amber-500/25 via-orange-400/5 to-transparent",
        description: "The ecosystem is coming online. Your technical roadmap is fresh and ready for manifestation."
      };
    } else if (hour >= 12 && hour < 17) {
      return { 
        id: 'afternoon',
        greeting: "Good Afternoon", 
        status: "Peak Manifestation", 
        icon: "☀️", 
        accent: "text-blue-500",
        bg: "from-blue-500/15 via-indigo-500/5 to-transparent",
        description: "Energy levels are at peak efficiency. The global grid is buzzing with architectural activity."
      };
    } else if (hour >= 17 && hour < 21) {
      return { 
        id: 'evening',
        greeting: "After Work", 
        status: "Evening Sync", 
        icon: "🌆", 
        accent: "text-rose-500",
        bg: "from-rose-500/20 via-purple-500/10 to-transparent",
        description: "Reviewing the day's deployments. The sector is cooling down, but your influence remains high."
      };
    } else {
      return { 
        id: 'night',
        greeting: "Night Owl Mode", 
        status: "Deep Focus Protocol", 
        icon: "🦉", 
        accent: "text-purple-400",
        bg: "from-purple-900/40 via-indigo-900/15 to-transparent",
        description: "The grid is quiet. Perfect conditions for deep architectural synthesis and neural focus."
      };
    }
  }, []);

  const handleStartScan = () => {
    setIsScannerOpen(true);
    setIsScanning(true);
    // Simulate finding a node after 3 seconds
    setTimeout(() => {
      setIsScanning(false);
    }, 3000);
  };

  return (
    <div className="space-y-8 md:space-y-12 animate-fade-in pb-32">
      {/* Immersive Time-Aware Header */}
      <section className={`relative rounded-[2.5rem] md:rounded-[3.5rem] p-8 md:p-16 overflow-hidden border transition-all duration-1000 ${isDark ? 'bg-vortex-darkCard border-vortex-darkBorder' : 'bg-white border-slate-200 shadow-2xl'}`}>

        {/* Dynamic Background Layers */}
        <div className={`absolute inset-0 bg-gradient-to-br ${timeContext.bg} pointer-events-none transition-all duration-1000`}></div>

        {/* Night Owl Mode Background: Twinkling Star Field */}
        {timeContext.id === 'night' && (
          <div className="absolute inset-0 pointer-events-none opacity-50">
            {[...Array(60)].map((_, i) => (
              <div 
                key={i} 
                className="absolute bg-white rounded-full animate-pulse"
                style={{ 
                  width: Math.random() * 2 + 0.5 + 'px', 
                  height: Math.random() * 2 + 0.5 + 'px', 
                  top: Math.random() * 100 + '%', 
                  left: Math.random() * 100 + '%',
                  animationDelay: Math.random() * 4 + 's',
                  animationDuration: Math.random() * 3 + 2 + 's',
                  opacity: Math.random() * 0.8 + 0.2
                }}
              ></div>
            ))}
          </div>
        )}

        {/* Good Morning Mode Background: Volumetric Rays */}
        {timeContext.id === 'morning' && (
          <div className="absolute inset-0 pointer-events-none overflow-hidden">
            <div className="absolute -top-40 -left-40 w-[800px] h-[800px] bg-amber-500/10 rounded-full blur-[120px] animate-glow-pulse"></div>
            <div className="absolute top-0 left-1/4 w-[10px] h-[200%] bg-gradient-to-b from-amber-400/10 to-transparent rotate-[25deg] transform-origin-top blur-md"></div>
          </div>
        )}

        {/* Scan Button - Top Right */}
        <div className="absolute top-8 right-8 z-20">
          <button 
            onClick={handleStartScan}
            className={`flex items-center gap-3 px-6 py-3 rounded-2xl border transition-all hover:scale-105 active:scale-95 shadow-xl backdrop-blur-md ${isDark ? 'bg-indigo-600/10 border-indigo-500/30 text-indigo-400 hover:bg-indigo-600 hover:text-white' : 'bg-white/80 border-slate-200 text-indigo-600 hover:bg-indigo-600 hover:text-white'}`}
          >
            <span className="text-lg">📷</span>
            <span className="text-[10px] font-black uppercase tracking-widest">Scan Node</span>
          </button>
        </div>

        <div className="relative z-10 space-y-6 md:space-y-10 max-w-5xl">
          <div className="flex flex-wrap items-center gap-4">
            <div className={`px-4 md:px-5 py-1.5 md:py-2 rounded-2xl border border-current bg-current/10 text-[9px] md:text-[11px] font-black uppercase tracking-[0.4em] flex items-center gap-3 ${timeContext.accent} shadow-xl backdrop-blur-md`}>
              <span className="text-sm md:text-lg leading-none">{timeContext.icon}</span>
              <span className="animate-pulse">{timeContext.status}</span>
            </div>
          </div>

          <div className="space-y-3 md:space-y-4">
            <h1 className="text-4xl md:text-8xl font-black tracking-tighter leading-[0.9] transition-all duration-700">
              {timeContext.greeting},<br />
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-500 via-purple-500 to-indigo-600">
                {currentUser?.name.split(' ')[0]}
              </span>.
            </h1>
            <p className="text-base md:text-2xl opacity-60 font-medium leading-relaxed tracking-tight max-w-2xl italic">
              {timeContext.description}
            </p>
          </div>

          <div className="flex flex-wrap gap-4 pt-2 md:pt-4">
            <button className="flex-1 md:flex-none bg-indigo-600 hover:bg-indigo-700 text-white px-8 md:px-12 py-4 md:py-5 rounded-[1.5rem] md:rounded-3xl font-black text-[10px] md:text-xs uppercase tracking-widest hover:scale-105 transition-all shadow-2xl shadow-indigo-600/40 active:scale-95">
              Initiate Build
            </button>
          </div>
        </div>
      </section>

      {/* Feed Section */}
      <div className="space-y-6 md:space-y-10 px-1 md:px-0">
        <div className="flex flex-col md:flex-row md:items-center justify-between border-b border-gray-500/10 pb-6 md:pb-8 gap-4">
          <div className="space-y-1">
            <h2 className="text-[10px] md:text-[11px] font-black uppercase tracking-[0.6em] text-indigo-500">Neural Feed</h2>
            <p className="text-xl md:text-2xl font-black tracking-tighter">Active Manifestations</p>
          </div>
        </div>

        <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-10">
          {projects.map(p => {
            const owner = state.users.find(u => u.id === p.ownerId);
            return (
              <div key={p.id} className={`group rounded-[2.5rem] md:rounded-[3rem] border overflow-hidden transition-all hover:-translate-y-3 ${isDark ? 'bg-vortex-darkCard border-vortex-darkBorder hover:border-indigo-500/40' : 'bg-white border-slate-200 shadow-xl'}`}>
                <div className="h-48 md:h-56 overflow-hidden relative">
                  <img src={p.image || 'https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?auto=format&fit=crop&q=80&w=800'} className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110" alt={p.title} />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent"></div>
                  <div className="absolute bottom-4 md:bottom-6 left-6 md:left-8 flex items-center gap-3 md:gap-4">
                     <div className="relative">
                       <img src={owner?.avatar} className="w-8 h-8 md:w-10 md:h-10 rounded-xl md:rounded-2xl border-2 border-white/20 shadow-2xl" alt="" />
                       {owner?.isPrime && <div className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-amber-500 rounded-full border-2 border-black"></div>}
                     </div>
                     <div className="space-y-0.5">
                       <p className="text-[11px] md:text-xs font-black text-white">{owner?.name}</p>
                       <p className="text-[7px] md:text-[8px] font-black uppercase text-white/50 tracking-widest">Architect</p>
                     </div>
                  </div>
                </div>
                <div className="p-8 md:p-10 space-y-5 md:space-y-6">
                  <div className="space-y-2 md:space-y-3">
                    <h3 className="text-xl md:text-2xl font-black tracking-tight leading-tight group-hover:text-indigo-500 transition-colors">{p.title}</h3>
                    <p className="text-xs md:text-sm opacity-50 line-clamp-2 leading-relaxed font-medium">{p.description}</p>
                  </div>
                  <div className="flex items-center justify-between pt-6 md:pt-8 border-t border-gray-500/10">
                    <div className="flex gap-4 md:gap-8">
                      <button onClick={() => onReact(p.id, 'like')} className="flex items-center gap-2 text-[10px] md:text-xs font-black opacity-30 hover:opacity-100 hover:text-indigo-500 transition-all group/btn">
                        <span className="text-base md:text-lg group-hover/btn:scale-125 transition-transform">🚀</span> {p.likes.toLocaleString()}
                      </button>
                    </div>
                    <button className="text-[8px] md:text-[10px] font-black text-indigo-500 uppercase tracking-widest hover:translate-x-2 transition-transform">Sync Node</button>
                  </div>
                </div>
              </div>
            );
          })}
        </section>
      </div>

      {/* QR Scanner Modal */}
      {isScannerOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in duration-300">
          <div className={`w-full max-w-lg rounded-[4rem] border-2 p-10 space-y-8 animate-in zoom-in-95 relative overflow-hidden ${isDark ? 'bg-vortex-darkCard border-indigo-500/20' : 'bg-white border-slate-200'}`}>
            <div className="text-center space-y-2">
              <h3 className="text-2xl font-black uppercase tracking-tighter">Neural Node Scanner</h3>
              <p className="text-[10px] font-black uppercase tracking-widest opacity-30">Targeting global architect identity</p>
            </div>

            <div className="relative aspect-square rounded-[3rem] overflow-hidden bg-black border-4 border-indigo-500/30 group">
              {/* Simulated Camera Feed */}
              <div className="absolute inset-0 opacity-40 bg-[url('https://images.unsplash.com/photo-1550751827-4bd374c3f58b?auto=format&fit=crop&q=80&w=800')] bg-cover bg-center grayscale contrast-125"></div>

              {/* UI Overlay */}
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                 <div className="w-64 h-64 border-2 border-indigo-500/50 rounded-3xl relative">
                    <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-indigo-500 rounded-tl-xl"></div>
                    <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-indigo-500 rounded-tr-xl"></div>
                    <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-indigo-500 rounded-bl-xl"></div>
                    <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-indigo-500 rounded-br-xl"></div>

                    {/* Scanning Line */}
                    {isScanning && (
                      <div className="absolute inset-x-0 h-1 bg-indigo-500 shadow-[0_0_20px_rgba(99,102,241,0.8)] animate-scan"></div>
                    )}
                 </div>
              </div>

              {/* Status Indicator */}
              <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/80 rounded-full border border-white/10 backdrop-blur-md">
                 <p className="text-[9px] font-black uppercase tracking-widest text-indigo-400">
                   {isScanning ? 'SEARCHING_NEURAL_SPACE...' : 'NODE_LOCKED_PENDING_AUTH'}
                 </p>
              </div>
            </div>

            <div className="space-y-4">
              <input 
                type="text" 
                placeholder="Or manual node ID entry..."
                className={`w-full px-6 py-4 rounded-2xl text-xs font-black uppercase tracking-widest outline-none border-2 transition-all ${isDark ? 'bg-black/40 border-white/5 focus:border-indigo-500 text-white' : 'bg-slate-50 border-slate-200 focus:border-indigo-500'}`}
              />
              <div className="flex gap-4">
                <button 
                  onClick={() => setIsScannerOpen(false)}
                  className="flex-1 py-5 rounded-3xl font-black text-[10px] uppercase tracking-widest border border-gray-500/10"
                >
                  ABORT
                </button>
                <button 
                  className="flex-[2] py-5 bg-indigo-600 text-white rounded-3xl font-black text-[10px] uppercase tracking-widest shadow-2xl shadow-indigo-600/30"
                >
                  ACQUIRE_TARGET
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useMemo, useState } from 'react';
import { User, Project } from '../types';
import { RANK_METRICS } from '../constants';

interface UserProfileProps {
  user: User;
  isSelf: boolean;
  isFollowing: boolean;
  onFollow: (id: string) => void;
  onMessage: (id: string) => void;
  onTalkToAssistant: () => void;
  onTogglePrivacy?: () => void;
  projects: Project[];
  isDark: boolean;
  allUsers: User[];
  globalIndex: number;
  onUpdateProfile?: (userId: string, updates: Partial<User>) => void;
}

const UserProfile: React.FC<UserProfileProps> = ({ 
  user, isSelf, isFollowing, onFollow, onMessage, 
  onTalkToAssistant, projects, isDark, globalIndex, onUpdateProfile 
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [isSharing, setIsSharing] = useState(false);

  const [editName, setEditName] = useState(user.name);
  const [editBio, setEditBio] = useState(user.bio);
  const [editBanner, setEditBanner] = useState(user.banner);
  const [editSkills, setEditSkills] = useState(user.skills.join(', '));
  const [editPrivacy, setEditPrivacy] = useState(user.isPrivate);

  const rankDef = useMemo(() => {
    return RANK_METRICS.find(r => r.tier === user.rank) || RANK_METRICS[RANK_METRICS.length - 1];
  }, [user.rank]);

  const handleSave = () => {
    onUpdateProfile?.(user.id, {
      name: editName,
      bio: editBio,
      banner: editBanner,
      skills: editSkills.split(',').map(s => s.trim()).filter(s => s),
      isPrivate: editPrivacy
    });
    setIsEditing(false);
  };

  const isProfileLocked = user.isPrivate && !isSelf;

  // Generate QR link
  const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=${encodeURIComponent(`vortex://profile/${user.id}`)}&color=6366f1&bgcolor=ffffff&margin=10`;

  return (
    <div className="max-w-6xl mx-auto animate-slide-up pb-32">
      <div className="relative mb-28 group/banner">
        <div className={`h-80 md:h-[450px] rounded-[4rem] shadow-3xl overflow-hidden relative transition-all duration-1000 ${isDark ? 'bg-indigo-950/20' : 'bg-slate-100'}`}>
          <img src={isProfileLocked ? 'https://images.unsplash.com/photo-1557683316-973673baf926?auto=format&fit=crop&q=80&w=1600' : user.banner} className={`w-full h-full object-cover ${isProfileLocked ? 'blur-md opacity-40' : ''}`} alt="Banner" />
          <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent"></div>
        </div>

        <div className="absolute -bottom-24 left-10 right-10 flex flex-col md:flex-row items-center md:items-end gap-10">
          <div className="relative group shrink-0">
            <div className={`absolute -inset-2 bg-gradient-to-br ${user.isPrime ? 'from-amber-400 to-amber-600' : 'from-indigo-500 to-purple-600'} rounded-[4rem] blur opacity-40 group-hover:opacity-80 transition duration-1000`}></div>
            <img src={isProfileLocked ? 'https://www.gravatar.com/avatar/00000000000000000000000000000000?d=mp&f=y' : user.avatar} className="relative w-48 h-48 md:w-56 md:h-56 rounded-[3.8rem] border-8 border-black shadow-4xl object-cover z-10" alt={user.name} />
          </div>

          <div className="flex-1 text-center md:text-left pb-6 space-y-4">
            <h1 className="text-5xl md:text-7xl font-black tracking-tighter text-white drop-shadow-2xl leading-none">{user.name}</h1>
            <div className="flex flex-wrap items-center justify-center md:justify-start gap-3">
              <span className="text-lg font-bold text-white/60 tracking-widest font-mono">@{user.name.toLowerCase().replace(/\s/g, '_')}</span>
              {user.isPrime && <span className="px-4 py-1.5 bg-amber-500 text-black rounded-full text-[9px] font-black uppercase tracking-widest shadow-lg shadow-amber-500/20">VORTEX_PRIME</span>}
            </div>
          </div>

          <div className="pb-8 flex flex-wrap justify-center gap-4">
             {isSelf ? (
               <>
                <button onClick={() => setIsEditing(true)} className="px-8 py-5 bg-indigo-600 text-white rounded-3xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-600/40 hover:scale-105 active:scale-95 transition-all">EDIT</button>
                <button onClick={() => setIsSharing(true)} className={`px-8 py-5 rounded-3xl font-black text-xs uppercase tracking-widest transition-all shadow-xl ${isDark ? 'bg-white/10 text-white border border-white/10' : 'bg-slate-100 text-slate-900 border border-slate-200'}`}>SHARE ID</button>
               </>
             ) : !isProfileLocked && (
                <button onClick={() => onFollow(user.id)} className={`px-10 py-5 rounded-3xl font-black text-xs uppercase tracking-widest transition-all shadow-2xl ${isFollowing ? 'bg-slate-500/10 text-slate-500 border border-slate-500/20' : 'bg-indigo-600 text-white shadow-indigo-600/30'}`}>
                  {isFollowing ? 'CONNECTED' : 'FOLLOW'}
                </button>
             )}
          </div>
        </div>
      </div>

      <section className={`mt-32 p-12 rounded-[4rem] border shadow-4xl flex flex-wrap items-center justify-between gap-12 relative overflow-hidden ${isDark ? 'bg-vortex-darkCard border-vortex-darkBorder' : 'bg-white border-slate-100'}`}>
        <div className="flex items-center gap-16">
          <Stat label="Global Rank" value={`#${globalIndex}`} sub="Deterministic Score" isPrime={user.isPrime} />
          <div className="w-px h-20 bg-gray-500/10"></div>
          <Stat label="Reputation" value={`${user.reputation}%`} sub="Verified" />
        </div>
      </section>

      {/* Share ID Modal */}
      {isSharing && (
