            <img src={isProfileLocked ? 'https://www.gravatar.com/avatar/00000000000000000000000000000000?d=mp&f=y' : user.avatar} className="relative w-48 h-48 md:w-56 md:h-56 rounded-[3.8rem] border-8 border-black shadow-4xl object-cover z-10" alt={user.name} />
