            description: { type: Type.STRING },
            techStack: { type: Type.ARRAY, items: { type: Type.STRING } },
            architecture: { type: Type.STRING },
            roadmap: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  label: { type: Type.STRING },
                  status: { type: Type.STRING }
                }
              }
            },
            starterFiles: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
